INSERT INTO `step` VALUES
('Abdominals Stretch Variation Four',1,'Lay on a ball or a Bosu ball with your feet firmly planted on the floor.'),
('Abdominals Stretch Variation Four',2,'Lean all the way back until you feel a stretch in your abdomen.'),
('Abdominals Stretch Variation Four',3,'Crunch upwards and hold for a 1-2 count.'),
('Abdominals Stretch Variation Four',4,'Slowly return to the starting position and repeat.'),
('Abdominals Stretch Variation One',1,'Lay on your stomach on the floor with your forearms flat on the ground.'),
('Abdominals Stretch Variation One',2,'Extend your elbows and push your upper body upwards.'),
('Abdominals Stretch Variation One',3,'Push your upper body upwards until you feel a stretch in your abs, then return to the starting position and repeat.'),
('Abdominals Stretch Variation Three',1,'Stand upright.'),
('Abdominals Stretch Variation Three',2,'After completing the desired amount of reps with the left arm, switch to the right arm and lean to the left.'),
('Abdominals Stretch Variation Three',3,'Reach up with your left arm and then lean slowly to the right. Lean until a stretch is felt in the obliques.'),
('Abdominals Stretch Variation Two',1,'Stand upright.'),
('Abdominals Stretch Variation Two',2,'Reach with both hands upwards until you can interlock your fingers.'),
('Abdominals Stretch Variation Two',3,'With your hands above your head, lean back until a stretch is felt in the abdominals.'),
('Alphabet',1,'Sit on a box or bench'),
('Alphabet',2,'Keep one foot off the ground by pulling onto your knee, or by crossing one leg over the opposite knee.'),
('Alphabet',3,'Try to form the letters of the Alphabet with your foot.'),
('Alternating Bent Leg Raise',1,'Lie on your back, legs bent and lifted off the ground.'),
('Alternating Bent Leg Raise',2,'Lower one leg to the ground until your foot taps the ground, keep your other leg up.'),
('Alternating Bent Leg Raise',3,'Alternate sides for the prescribed amount of reps.'),
('Alternating Heel Touch',1,'Lie on your back, knees bent, feet flat.'),
('Alternating Heel Touch',2,'Reach right hand to right heel.'),
('Alternating Heel Touch',3,'Switch sides, left hand to left heel. Repeat.'),
('Alternating Pole Rotation',1,'Start with the pole in front of you with an overhand wider than shoulder width grip.'),
('Alternating Pole Rotation',2,'Rotate one arm overhead and behind while keeping the other arm in front of you.'),
('Alternating Pole Rotation',3,'Then rotate the other arm.'),
('Alternating Pole Rotation',4,'Bring the original arm back to the starting position, then the other arm. Repeat.'),
('Ankle Circle',1,'Sit or stand, lift one foot slightly off the ground.'),
('Ankle Circle',2,'Rotate your ankle in a circular motion.'),
('Ankle Circle',3,'Complete the allotted amount of reps, then switch directions and repeat on the other foot.'),
('Arms Pulling Straps Airplane Prone On The Box',1,'Lie prone on the box, chest just off edge, arms holding straps.'),
('Arms Pulling Straps Airplane Prone On The Box',2,'Start with arms down, palms facing in, shoulders set away from ears.'),
('Arms Pulling Straps Airplane Prone On The Box',3,'Lift arms out to a T, squeezing shoulder blades, keeping neck long.'),
('Arms Pulling Straps Airplane Prone On The Box',4,'Lower with control, maintain neutral spine, repeat for smooth controlled reps.'),
('Arms Pulling Straps Plow Prone On The Box',1,'Lie prone on the box, chest just off edge, arms holding straps overhead.'),
('Arms Pulling Straps Plow Prone On The Box',2,'Start with arms long, palms down, shoulders depressed and neck neutral.'),
('Arms Pulling Straps Plow Prone On The Box',3,'Pull arms down toward hips, squeezing lats while keeping torso stable.'),
('Arms Pulling Straps Plow Prone On The Box',4,'Return slowly to start, maintaining control and continuous tension on straps.'),
('Back Rowing Preps Airplane Seated',1,'Sit tall with legs extended, arms holding straps at shoulder height.'),
('Back Rowing Preps Airplane Seated',2,'Start with arms forward, palms facing forward, shoulders relaxed.'),
('Back Rowing Preps Airplane Seated',3,'Pull arms out to a T, squeezing upper back without leaning.'),
('Back Rowing Preps Airplane Seated',4,'Return slowly to start, maintaining upright posture and controlled tension.'),
('Back Rowing Preps Bicep Curls Seated',1,'Sit tall with legs extended, arms holding straps at shoulder height.'),
('Back Rowing Preps Bicep Curls Seated',2,'Start with arms straight, palms facing up, shoulders relaxed.'),
('Back Rowing Preps Bicep Curls Seated',3,'Bend elbows, curling hands toward shoulders without moving torso.'),
('Back Rowing Preps Bicep Curls Seated',4,'Extend arms slowly, maintaining control and constant tension on straps.'),
('Back Rowing Preps Open Elbow Seated',1,'Sit tall with legs extended, arms holding straps at shoulder height.'),
('Back Rowing Preps Open Elbow Seated',2,'Start with elbows bent, hands near chest, palms facing inward.'),
('Back Rowing Preps Open Elbow Seated',3,'Open elbows wide, rotating shoulders externally while keeping chest lifted.'),
('Back Rowing Preps Open Elbow Seated',4,'Return with control, maintaining upright posture and steady strap tension.'),
('Back Rowing Preps Roll Down With Bicep Curl Seated',1,'Sit tall with legs extended, arms holding straps, elbows straight.'),
('Back Rowing Preps Roll Down With Bicep Curl Seated',2,'Roll spine down sequentially while bending elbows into a bicep curl.'),
('Back Rowing Preps Roll Down With Bicep Curl Seated',3,'Pause briefly, keeping shoulders relaxed and core engaged.'),
('Back Rowing Preps Roll Down With Bicep Curl Seated',4,'Reverse the roll up, extending arms forward with controlled tension.'),
('Back Rowing Preps Roll Down With Obliques',1,'Sit tall with legs extended, arms holding straps at chest height.'),
('Back Rowing Preps Roll Down With Obliques',2,'Rotate torso slightly, engaging obliques as you begin rolling back.'),
('Back Rowing Preps Roll Down With Obliques',3,'Maintain rotation and bend elbows, keeping shoulders relaxed and spine controlled.'),
('Back Rowing Preps Roll Down With Obliques',4,'Roll back up with control, returning to center without losing tension.'),
('Back Rowing Preps Triceps Seated',1,'Sit tall with legs extended, arms holding straps at chest height.'),
('Back Rowing Preps Triceps Seated',2,'Start with elbows bent, upper arms close to sides.'),
('Back Rowing Preps Triceps Seated',3,'Extend elbows fully, pressing straps back while keeping torso upright.'),
('Back Rowing Preps Triceps Seated',4,'Bend elbows slowly to return, maintaining control and steady tension.'),
('Backstroke Prep Lying On Box',1,'Lie prone on the box, chest supported, arms holding straps forward.'),
('Backstroke Prep Lying On Box',2,'Start with arms straight, palms facing down, shoulders relaxed.'),
('Backstroke Prep Lying On Box',3,'Pull arms back in a sweeping motion, engaging upper back.'),
('Backstroke Prep Lying On Box',4,'Return to start with control, keeping neck long and torso stable.'),
('Backward Arm Circle',1,'Hold your arms out to your sides.'),
('Backward Arm Circle',2,'Rotate your arms backwards in small circles.'),
('Band Bayesian Curl',1,'Attach band to a low anchor point. Point your palms straight forward.'),
('Band Bayesian Curl',2,'Flex your elbow until you feel your biceps contract. Then fully extend elbows.'),
('Band Bayesian Hammer Curl',1,'Attach band to a low anchor point. Use a neutral grip.'),
('Band Bayesian Hammer Curl',2,'Flex your elbow until you feel your biceps contract. Then fully extend elbows.'),
('Band Bayesian Reverse Curl',1,'Attach band to a low anchor point. . Point your palms toward your thighs.'),
('Band Bayesian Reverse Curl',2,'Flex your elbow until you feel your biceps contract. Then fully extend elbows.'),
('Band Bench Fly',1,'Lie on bench holding band handles with arms extended above chest.'),
('Band Bench Fly',2,'Lower arms out wide in a controlled arc, keeping slight bend in elbows.'),
('Band Bench Fly',3,'Bring arms back together over chest, squeezing pecs at the top.'),
('Band Bench Press',1,'Lie on bench with band looped behind your back.'),
('Band Bench Press',2,'Lower hands toward chest while keeping elbows at a comfortable angle.'),
('Band Bench Press',3,'Press upward and squeeze chest at the top, maintaining band tension.'),
('Band Bent Over Row',1,'Stand on band with feet hip-width, holding handles with palms facing in.'),
('Band Bent Over Row',2,'Hinge at hips, keeping back flat and elbows close to ribs.'),
('Band Bent Over Row',3,'Pull handles toward torso, squeeze back, then lower slowly with control.'),
('Band Calf Raise',1,'Attach band to a low anchor point.'),
('Band Calf Raise',2,'Take a few steps away until the band is taut.'),
('Band Calf Raise',3,'Lean back slightly. Raise your heels straight up and down'),
('Band Chest Press',1,'Stand in the middle of the two bands with feet shoulder-width apart. Step forward with one foot to create tension in the bands.'),
('Band Chest Press',2,'Hold one band in each hand, palms facing forward. Start the exercise with your arms extended in front of you, keeping a slight bend in your elbows.'),
('Band Chest Press',3,'Lower your arms to the sides of your chest, maintaining control of the band.'),
('Band Chest Press',4,'Push your arms back up to the starting position, keeping your core engaged and maintaining control of the band.'),
('Band Crunch',1,'Place the band at the highest anchor point you have available. Grab both ends of the band and fall into a kneeling position.'),
('Band Crunch',2,'Push your hips back flexing at the spine.'),
('Band Crunch',3,'Squeeze your abs and then extend at the hips and spine back to the starting position.'),
('Band Curl',1,'Stand with your feet shoulder-width apart, with the band under both feet.'),
('Band Curl',2,'Grasp the handles of the band with both hands, keeping your arms straight and extended in front of you.'),
('Band Curl',3,'Keep your back straight, abs engaged, and shoulders relaxed as you curl your hands towards your shoulders, bending at the elbows.'),
('Band Face Pull',1,'Anchor the band at eye level. Take a few steps away until the band is taut.'),
('Band Face Pull',2,'Use an overhand grip with both hands. Pull the band to the bridge of your nose flaring your elbows out.'),
('Band Floor Press',1,'Lie on your back holding band loops with elbows resting on the floor.'),
('Band Floor Press',2,'Press arms straight up until elbows extend without locking.'),
('Band Floor Press',3,'Lower elbows back to floor under control, keeping tension throughout.'),
('Band Front Raise',1,'Stand on the band with one or 2 feet depending on how heavy you want the band to be.'),
('Band Front Raise',2,'With your elbows extended raise your fists straight up to the ceiling until they are at eye level.'),
('Band Glute Kickback',1,'Get into a quadruped position. Loop the band around both of your wrists and one of your feet.'),
('Band Glute Kickback',2,'Extend your knee and hip straight back until you feel like contraction in the glutes.'),
('Band Glute Kickback',3,'Flex at the knee until back in the starting position.'),
('Band Goblet Squat',1,'Stand with a shoulder width grip. Both feet should be on the band with the band looped over both hands.'),
('Band Goblet Squat',2,'Push your butt back and also break at the knees.'),
('Band Goblet Squat',3,'Try to hit parallel depth (bottom of your leg should be parallel with the ground). If you can\'t tell your squat depth, then try squatting in front of a mirror and watch your form.'),
('Band Good Morning',1,'Anchor the band at hip level. Take a few steps away until the band is taut.'),
('Band Good Morning',2,'Push your hips back while keeping your back flat until you feel a stretch in your hamstrings.'),
('Band Half Kneeling Single Arm Pulldown',1,'Kneel facing anchor with band overhead, holding the end of the band in one hand.'),
('Band Half Kneeling Single Arm Pulldown',2,'Keep torso tall and pull elbow down toward your hip.'),
('Band Half Kneeling Single Arm Pulldown',3,'Squeeze lat at the bottom, then return arm slowly to starting position.'),
('Band High Curl',1,'Anchor a band to a high point.'),
('Band High Curl',2,'Start with your feet staggered and your elbows high.'),
('Band High Curl',3,'Flex your elbows while keeping your arms high. Curl the band to your forehead.'),
('Band High Face Pull',1,'Start with a band anchored to a high point. Stagger your stance.'),
('Band High Face Pull',2,'Pull the band to the bridge of your nose.'),
('Band High Hammer Curl',1,'Start with the band anchored to something high with your feet staggered and a neutral grip.'),
('Band High Hammer Curl',2,'Keep your elbows high. Curl until your fists are at your forehead.'),
('Band High Reverse Curl',1,'Start with a band attached to a high point, your feet staggered, and an overhand grip.'),
('Band High Reverse Curl',2,'Flex your elbows pulling your forearms to your biceps. Your fists should land by your forehead.'),
('Band Hip Abduction',1,'Attach the band around your ankle. Stand with feet hip-width apart, feet facing forward, and hands on hips.'),
('Band Hip Abduction',2,'Lift your right leg away from your body to the side, keeping your knee straight. This is your starting position.'),
('Band Hip Abduction',3,'Maintaining proper form, move your right leg as far to the side as you can, keeping your left leg planted firmly on the ground. Hold for a second and then return your right leg to the starting position.'),
('Band Hip Adduction',1,'Attach a band to a stable anchor point, such as a door handle or post.'),
('Band Hip Adduction',2,'Stand with feet shoulder-width apart and place the band around your ankles.'),
('Band Hip Adduction',3,'Keeping your feet together, move your legs out to the sides and then back to the midline of your body. Repeat for the desired number of repetitions.'),
('Band Horizontal Shrug',1,'Anchor the band at shoulder height. Take a few steps away until the band is taut.'),
('Band Horizontal Shrug',2,'Retract your shoulder blades straight back in schools. Then protract to the starting position.'),
('Band Internally Rotated Chest Fly',1,'Start with both feet hip-width apart and step on the middle of the band with both feet. Hold the handles of the band in each hand and position the band above your chest, with your palms facing down.'),
('Band Internally Rotated Chest Fly',2,'Keeping your elbows slightly bent, slowly raise your arms out to the sides until they are parallel with the floor. Make sure to internally rotate your shoulder joints by bringing your shoulder blades together and rotating your forearms inward towards your torso.'),
('Band Internally Rotated Chest Fly',3,'Hold the position for a few seconds and then slowly lower your arms back to the starting position, keeping the internal rotation of your shoulder joints throughout the movement.'),
('Band Kneeling Pulldown',1,'Kneel facing anchor with band overhead and arms extended.'),
('Band Kneeling Pulldown',2,'Pull elbows down toward ribs while keeping chest tall.'),
('Band Kneeling Pulldown',3,'Squeeze lats at the bottom, then return slowly to full stretch.'),
('Band Kneeling Single Arm Pulldown',1,'Place the band at about eye level. Fall into a kneeling position.'),
('Band Kneeling Single Arm Pulldown',2,'The knee that is on the ground should be the same side as the working arm. Stick your chest out.'),
('Band Kneeling Single Arm Pulldown',3,'And then pull your elbow straight back. Flex your lats and then extend into the starting position.'),
('Band Lateral Raise',1,'Grab the band at shoulder width. Raise your arms straight out to the side.'),
('Band Lateral Raise',2,'The band should scrape against your shirt.'),
('Band Leg Press',1,'Lay flat on the ground with your head by the anchor point of the band, which should be 6 to 12 inches above your head'),
('Band Leg Press',2,'Place the band around your midfoot and extend at the knees and hip.'),
('Band Mid Lateral Raise',1,'Anchor a band to a point that is the same height as your fist when your arms are at your side and stand with the band crossing your body.'),
('Band Mid Lateral Raise',2,'While keeping your elbow mostly extended, lift your arm until it\'s parallel with the floor.'),
('Band Overhead Press',1,'Stand between the two anchored bands, grasp them with an overhand grip, and position the bands at shoulder level.'),
('Band Overhead Press',2,'Brace your core and push the bands overhead, fully extending your arms.'),
('Band Overhead Press',3,'Lower the bands back to shoulder level, keeping your core engaged and arms straight. Repeat for desired number of reps.'),
('Band Overhead Tricep Extension',1,'Stand with one or both feet on band. Go up and over your head with the band to the starting position.'),
('Band Overhead Tricep Extension',2,'Flex and extend your elbows.'),
('Band Pallof Press',1,'Place the band at an anchor point that is shoulder height. Take a few steps away until the band is taut.'),
('Band Pallof Press',2,'Start with your fingers interlocked around the band and your fists connected to your chest.'),
('Band Pallof Press',3,'Extend at the elbows pressing the band away from your body until your elbows are fully extended.'),
('Band Pallof Press To Wood Chopper',1,'Stand sideways to band, hold handle at chest, and brace your core.'),
('Band Pallof Press To Wood Chopper',2,'Press arms straight forward, resisting rotation.'),
('Band Pallof Press To Wood Chopper',3,'Rotate torso and pull band across body in a wood chopper motion, then return.'),
('Band Press Around',1,'Stand with band behind you and hold loop at chest height.'),
('Band Press Around',2,'Press one arm forward and across your body in a sweeping arc.'),
('Band Press Around',3,'Squeeze chest at full extension, then return slowly and switch sides.'),
('Band Pull Apart',1,'Grab the band with a shoulder width grip. Point your arms straight in front of you.'),
('Band Pull Apart',2,'Retract your shoulder blades and shoulder joint until the band taps your chest.'),
('Band Pull Around',1,'Stand sideways to anchor and hold band with arm slightly extended.'),
('Band Pull Around',2,'Pull arm across your body in a smooth arc without rotating torso.'),
('Band Pull Around',3,'Squeeze chest at end range, then return slowly with control.'),
('Band Pullover',1,'Place the band just above our level. Take a few steps away until the band is taut.'),
('Band Pullover',2,'Push your hips back slightly. Extend and flex at the shoulder joint.'),
('Band Pullthrough',1,'Anchor the band to the lowest point possible. Straddle the band and then grab with both hands.'),
('Band Pullthrough',2,'Take a few steps away until the band is taut.'),
('Band Pullthrough',3,'Push your butt back until you feel a stretch in your hamstrings. Then extend the hips back into the starting position.'),
('Band Pushdown',1,'Place the band just above eye level. Take a few steps away until the band is taut.'),
('Band Pushdown',2,'Push your hips back slightly. Extend and flex at the elbows.'),
('Band Pushup',1,'Loop the band around your mid-back. The ends of the bands should be around your hands between your thumb and pointer finger.'),
('Band Pushup',2,'This exercise can be done from the knees or the toes depending on experience level.'),
('Band Pushup',3,'Begin by breaking at the elbows until your upper arm is by your side. Then extend at the elbows back into the top position.'),
('Band Rapunzel Pushdown',1,'Anchor the band to a high point and face away. Hold the band with both hands, placing your hands shoulder-width apart and keeping your elbows close to your body.'),
('Band Rapunzel Pushdown',2,'Slowly extend your arms downward, keeping your elbows close to your body. Push the band down as far as you can, feeling the contraction in your triceps.'),
('Band Rear Delt Fly',1,'Start by standing between the two anchored bands with your feet shoulder-width apart and the bands positioned at a high point.'),
('Band Rear Delt Fly',2,'Grasp the ends of each band with your hands, keeping your palms facing each other.'),
('Band Rear Delt Fly',3,'Keeping your arms slightly bent and your back straight, slowly pull the bands away from your body until your arms are extended straight out to the sides. Hold for a second, then slowly release back to the starting position. Repeat for desired reps.'),
('Band Reverse Curl',1,'Start by standing on the center of the band with both feet, shoulder-width apart.'),
('Band Reverse Curl',2,'Hold the band with both hands, palms facing down, arms extended straight in front of you.'),
('Band Reverse Curl',3,'Slowly curl your hands towards your shoulders, pulling the band tight, then lower your arms back to the starting position, keeping tension on the band throughout the exercise.'),
('Band Romanian Deadlift',1,'Stand on your band with both feet.'),
('Band Romanian Deadlift',2,'Hinge forward at the hips while keeping a flat back.'),
('Band Romanian Deadlift',3,'Hinge until you feel a stretch in your hamstrings.'),
('Band Romanian Deadlift',4,'Push your hips back forward until you are in a standing position.'),
('Band Row',1,'Stand on your band with both feet.'),
('Band Row',2,'Hinge forward at the hips while keeping a flat back.'),
('Band Row',3,'Let your arms hang freely, then pull your elbows straight back toward the ceiling.'),
('Band Seated Cervical Side Flexion',1,'Sit on a bench maintaining an upright posture'),
('Band Seated Cervical Side Flexion',2,'Wrap a ribbon/flat band around your head and hold the ends to the side of your head with one arm'),
('Band Seated Cervical Side Flexion',3,'Gently extend the arm till the band starts applying force onto the neck muscles.'),
('Band Seated Cervical Side Flexion Eccentric',1,'Sit on a bench maintaining an upright posture.'),
('Band Seated Cervical Side Flexion Eccentric',2,'Wrap a ribbon/flat band around your head and hold the ends to the side of your head with one arm.'),
('Band Seated Cervical Side Flexion Eccentric',3,'Gently extend the arm till the band starts applying force onto the neck muscles then bend your arm so that the band resistance is reduced but not eliminated.'),
('Band Seated Cervical Side Flexion Hold',1,'Sit on a bench maintaining an upright posture'),
('Band Seated Cervical Side Flexion Hold',2,'Wrap a ribbon/flat band around your head and hold the ends to the side of your head with one arm.'),
('Band Seated Cervical Side Flexion Hold',3,'Extend the elbow slightly till you feel the opposite side of your neck resisting the band'),
('Band Seated Pulldown',1,'Sit facing anchor with band overhead and arms extended.'),
('Band Seated Pulldown',2,'Pull elbows down toward ribs while keeping chest lifted.'),
('Band Seated Pulldown',3,'Squeeze lats at the bottom, then return slowly to full stretch.'),
('Band Seated Single Arm Pulldown',1,'Sit facing anchor with band overhead, holding handle in one hand.'),
('Band Seated Single Arm Pulldown',2,'Pull elbow down toward your hip while keeping chest tall.'),
('Band Seated Single Arm Pulldown',3,'Squeeze lat at the bottom, then return slowly to full stretch.'),
('Band Shoulder Y Raise',1,'Hold one end of a band with your arm to the side and behind your body.'),
('Band Shoulder Y Raise',2,'Hold the other end in front of your body (overhand grip).'),
('Band Shoulder Y Raise',3,'Move your arm away from your body and upward while externally rotating your shoulder.'),
('Band Shoulder Y Raise',4,'Finish with your arm over your head and thumb up'),
('Band Shrug',1,'Place the band under your feet. Stand upright.'),
('Band Shrug',2,'Elevate your shoulder blades and then depress back to the starting position.'),
('Band Side Bend',1,'Stand with band anchored low on one side, holding handle at hip.'),
('Band Side Bend',2,'Lean torso away from anchor, keeping hips and legs still.'),
('Band Side Bend',3,'Contract obliques to return upright, maintaining smooth control.'),
('Band Single Arm Bent Over Row',1,'Stand on band and hinge at hips, holding handle with arm extended.'),
('Band Single Arm Bent Over Row',2,'Pull elbow toward your hip, keeping back flat and shoulders square.'),
('Band Single Arm Bent Over Row',3,'Squeeze back at the top, then lower slowly to full stretch.'),
('Band Single Arm Chest Press',1,'Attach the band to an anchor point that is about shoulder height. Take a few steps away until the band is taut.'),
('Band Single Arm Chest Press',2,'Extend your shoulder joint and elbow across your body until your arm is fully extended.'),
('Band Single Arm Internally Rotated Chest Fly',1,'Stand sideways to anchor, hold band with arm slightly bent and palm turned inward.'),
('Band Single Arm Internally Rotated Chest Fly',2,'Bring arm across chest in a sweeping arc while keeping internal rotation.'),
('Band Single Arm Internally Rotated Chest Fly',3,'Squeeze chest at end range, then return slowly under control.'),
('Band Single Arm Lateral Raise',1,'Stand on band and hold handle or loop at your side with slight elbow bend.'),
('Band Single Arm Lateral Raise',2,'Raise arm out to the side until shoulder height, keeping torso still.'),
('Band Single Arm Lateral Raise',3,'Lower slowly under control, maintaining constant tension on the delt.'),
('Band Single Arm Overhead Press',1,'Loop the band under one of your feet. The other end of the bed should be in your hand between your thumb and pointer finger.'),
('Band Single Arm Overhead Press',2,'Press the band straight up towards the ceiling. Until your elbow is fully extended.'),
('Band Single Arm Pec Fly',1,'Attach the band to an anchor point that is about shoulder height. Take a few steps away until the band is taut.'),
('Band Single Arm Pec Fly',2,'Extend your shoulder joint and bring your arm across your body until you feel a contraction in your pecs.'),
('Band Single Arm Pulldown',1,'Anchor the band to a high point. Go into a seated position.'),
('Band Single Arm Pulldown',2,'Grab the loop of the band and pull your upper arm to your side.'),
('Band Single Arm Pushdown',1,'Stand with your feet shoulder-width apart and hold the band with your right hand, with your arm at your side.'),
('Band Single Arm Pushdown',2,'Flex and extend your elbow.'),
('Band Single Arm Row',1,'Anchor band to a stable point.'),
('Band Single Arm Row',2,'Step back until there is no slack in the band and hold the end of the band with one hand.'),
('Band Single Arm Row',3,'Pull through the elbow straight back.'),
('Band Single Arm Skullcrusher',1,'Stand facing away from a band which is anchored to a high point.'),
('Band Single Arm Skullcrusher',2,'Keep your elbow pointed forward, and extend and flex your elbow.'),
('Band Skullcrusher',1,'Anchor a band to a stable point.'),
('Band Skullcrusher',2,'Face away and begin with your elbows bent and fists by your temples.'),
('Band Skullcrusher',3,'Extend your elbows until your triceps contract.'),
('Band Spanish Squat',1,'Anchor a band to a stable point.'),
('Band Spanish Squat',2,'Place the loops of the band behind your knees.'),
('Band Spanish Squat',3,'Perform a normal squat and extend your knees against the band at the top.'),
('Band Squat',1,'Stand with a shoulder width grip. Both feet should be on the band with the band loops in each of your hand.'),
('Band Squat',2,'Push your butt back and also break at the knees.'),
('Band Squat',3,'Try to hit parallel depth (bottom of your leg should be parallel with the ground). If you can\'t tell your squat depth, then try squatting in front of a mirror and watch your form.'),
('Band Squat Hold Row',1,'Anchor the band to a stable point.'),
('Band Squat Hold Row',2,'Take a half squat position and hold there.'),
('Band Squat Hold Row',3,'Perform a row while holding the squat position.'),
('Band Squat Hold Single Arm Row',1,'Anchor the band to a stable point and take a half squat position.'),
('Band Squat Hold Single Arm Row',2,'Hold the band loop in one hand and pull your elbow straight back.'),
('Band Standing Chest Press',1,'Loop the band around your back. The two end loops in each of your hands.'),
('Band Standing Chest Press',2,'Extend your shoulder joint and elbow across your body until your arm is fully extended.'),
('Band Standing Good Morning',1,'Stand on band and loop it around upper back, feet hip-width apart.'),
('Band Standing Good Morning',2,'Hinge at hips while keeping back flat and slight bend in knees.'),
('Band Standing Good Morning',3,'Squeeze glutes to return to standing, maintaining band tension throughout.'),
('Band Tricep Kickback',1,'Anchor the band to a stable point.'),
('Band Tricep Kickback',2,'Hinge forward. Extend and flex at the elbow.'),
('Band Upright Row',1,'Stand with one or both feet on one end of a band. Take a double overhand roughly shoulder width grip.'),
('Band Upright Row',2,'Pull your elbows straight up the ceiling. Aim to get the band to chin level or slightly higher.'),
('Band Wood Chopper',1,'Anchor band at shoulder height. Stand sideways, feet shoulder-width, slight knee bend.'),
('Band Wood Chopper',2,'Grip band with both hands, arms extended.'),
('Band Wood Chopper',3,'Pull across body, rotating torso.'),
('Banded Side Walks',1,'Place a band either just below or above your knees.'),
('Banded Side Walks',2,'Get into a quarter squat position.'),
('Banded Side Walks',3,'Step side to side without letting there be any slack in the band to keep tension on the band.'),
('Barbell 30 Degree Shrug',1,'Hold barbell with a wide grip. Your arms should be at a roughly 30 degree angle.'),
('Barbell 30 Degree Shrug',2,'Pull your shoulders towards your ears instead of straight up toward the ceiling.'),
('Barbell Banded Back Squat',1,'Loop resistance bands under your feet and around the barbell. Stand shoulder-width apart.'),
('Barbell Banded Back Squat',2,'Brace your core, push hips back, and lower until thighs are parallel to the floor.'),
('Barbell Banded Back Squat',3,'Drive through your heels, extend hips and knees, and return to standing tall.'),
('Barbell Banded Deadlift',1,'Loop bands under your feet and around the barbell. Stand hip-width apart.'),
('Barbell Banded Deadlift',2,'Hinge at the hips, keep your back flat, and lower to grasp the bar.'),
('Barbell Banded Deadlift',3,'Drive through heels, extend hips and knees, and stand tall with shoulders back.'),
('Barbell Banded Front Squat',1,'Loop bands under your feet and around the anchors, bar resting on front delts.'),
('Barbell Banded Front Squat',2,'Keep chest tall, brace core, and lower until thighs reach parallel.'),
('Barbell Banded Front Squat',3,'Drive through midfoot, extend hips and knees, and return to standing upright.'),
('Barbell Banded Romanian Deadlift',1,'Loop bands under your feet or anchors and around the barbell. Stand tall with soft knees.'),
('Barbell Banded Romanian Deadlift',2,'Hinge at the hips, keeping the bar close and back straight throughout.'),
('Barbell Banded Romanian Deadlift',3,'Squeeze glutes, drive hips forward, and return to full standing position.'),
('Barbell Banded Split Squat',1,'Loop band under front foot and around barbell resting on your upper back.'),
('Barbell Banded Split Squat',2,'Lower back knee toward the floor while keeping front knee over ankle.'),
('Barbell Banded Split Squat',3,'Push through front heel and drive up to starting position under control.'),
('Barbell Behind The Back 30 Degree Shrug',1,'Hold barbell behind you with arms at a 30 degree angle with your torso.'),
('Barbell Behind The Back 30 Degree Shrug',2,'Shrug shoulders up and slightly back toward ears, keeping elbows locked.'),
('Barbell Behind The Back 30 Degree Shrug',3,'Pause briefly at the top, then lower under control to full stretch.'),
('Barbell Behind The Back Shrug',1,'Hold barbell behind your hips with overhand grip, arms straight.'),
('Barbell Behind The Back Shrug',2,'Shrug shoulders straight up toward ears without bending elbows.'),
('Barbell Behind The Back Shrug',3,'Lower slowly, maintaining tension in traps throughout the movement.'),
('Barbell Behind The Back Wrist Curl',1,'Stand straight and hold the barbell behind you using a pronated grip with your hands and feet shoulder-width apart.'),
('Barbell Behind The Back Wrist Curl',2,'Slowly curl your wrists in a semi-circular motion upwards.'),
('Barbell Behind The Back Wrist Curl',3,'Hold the barbell at the apex of the motion and then slowly lower the barbell back down to starting position.'),
('Barbell Behind The Neck Press',1,'Grip bar slightly wider than shoulders and rest it across upper traps.'),
('Barbell Behind The Neck Press',2,'Brace core, press bar upward until arms are fully extended overhead.'),
('Barbell Behind The Neck Press',3,'Lower bar slowly behind head under control and repeat.'),
('Barbell Behind The Neck Seated Overhead Press',1,'Take a roughly shoulder width grip. There should be a straight line from your elbow to fist (vertical forearms).'),
('Barbell Behind The Neck Seated Overhead Press',2,'Push your head foward and press the weight toward the ceiling by extending at the elbow joint and flexing at the shoulder joint.'),
('Barbell Behind The Neck Seated Overhead Press',3,'Press until your elbows are extended and push your head forward slightly.'),
('Barbell Bench Press',1,'Lay flat on the bench with your feet on the ground. With straight arms unrack the bar.'),
('Barbell Bench Press',2,'Lower the bar to your mid chest'),
('Barbell Bench Press',3,'Raise the bar until you\'ve locked your elbows.'),
('Barbell Bent Over Row',1,'Grab a barbell with a shoulder width pronated or supinated grip.'),
('Barbell Bent Over Row',2,'Bend forward at your hips while maintaining a flat back.'),
('Barbell Bent Over Row',3,'Pull the weight toward your upper abdomen.'),
('Barbell Bent Over Row',4,'Lower the weight in a controlled manner and repeat.'),
('Barbell Block Conventional Deadlift',1,'Stand with your mid-foot under the bar, plates should be on blocks, and grip the bar with your hands, about a shoulder width apart.'),
('Barbell Block Conventional Deadlift',2,'Bend your knees, then lift the bar by straightening your back. It is important to keep your back straight.'),
('Barbell Block Conventional Deadlift',3,'Stand to your full height and hold.'),
('Barbell Block Conventional Deadlift',4,'Lower the bar to the floor by bending your knees and keeping your back straight.'),
('Barbell Bradford Press',1,'Hold a barbell at shoulder height with a pronated grip.'),
('Barbell Bradford Press',2,'Press the barbell over your head.'),
('Barbell Bradford Press',3,'Lower it behind your head, then return to the front. Repeat for desired reps.'),
('Barbell Bulgarian Split Squat',1,'Find a box or bench that is roughly knee height or a few inches lower. (The lower the box is the lower the mobility requirement).'),
('Barbell Bulgarian Split Squat',2,'You can either place your toes or the top of your foot on the box. Point your front foot forward or slightly turned outwards and break at the knees and hips simultaneously.'),
('Barbell Bulgarian Split Squat',3,'Aim to get your front leg to hit parallel depth (hamstring parallel with the ground) or lower.'),
('Barbell Bulgarian Split Squat',4,'The further forward your front foot is, the longer the Range of Motion is at your hips. The further back your front foot is, the longer the ROM at your knees.'),
('Barbell Calf Jump',1,'Stand with your feet shoulder-width apart and your knees slightly bent.'),
('Barbell Calf Jump',2,'Shift your weight onto the balls of your feet and raise stay flat footed. Using your calf muscles, mimic a jumping motion but don\'t leave the floor.'),
('Barbell Calf Jump',3,'Explode onto your tip toes and hold for a second.'),
('Barbell Calf Jump',4,'Bring your heels back to the floor then initiate the next rep.'),
('Barbell Calf Raises',1,'Place the bar on your back'),
('Barbell Calf Raises',2,'Start with feet flat on the ground'),
('Barbell Calf Raises',3,'Extend your heels upwards while keeping your knees stationary, and pause at the contracted position.'),
('Barbell Calf Raises',4,'Slowly return to the starting position. Repeat.'),
('Barbell Clean And Jerk',1,'Stand with feet hip-width apart, grip the bar just outside your knees. Pull the bar from the floor by driving through your legs, keeping your back straight.'),
('Barbell Clean And Jerk',2,'As the bar reaches your hips, extend explosively, shrug, and drop under to catch it in a front squat position with elbows high. Stand up tall.'),
('Barbell Clean And Jerk',3,'Dip slightly, then drive through your legs to push the bar overhead.'),
('Barbell Clean And Jerk',4,'Stabilize the bar overhead, lock arms, then bring feet together before lowering the bar safely.'),
('Barbell Clean And Press',1,'Stand with feet hip-width, grip barbell just outside thighs.'),
('Barbell Clean And Press',2,'Explosively extend hips and pull bar to shoulders in one motion.'),
('Barbell Clean And Press',3,'Press overhead until arms lock out, then lower bar under control.'),
('Barbell Close Grip Bench Press',1,'Lay flat on the bench with your feet on the ground. With a narrow grip on the bar, straighten your arms'),
('Barbell Close Grip Bench Press',2,'Lower the bar to your lower-mid chest'),
('Barbell Close Grip Bench Press',3,'Slowly raise the bar until you\'ve locked your elbows.'),
('Barbell Conventional Pause Deadlift',1,'Set up for a standard deadlift, grip the barbell.'),
('Barbell Conventional Pause Deadlift',2,'Lift, pause at knee height.'),
('Barbell Conventional Pause Deadlift',3,'Hold briefly, then complete the lift; reset and repeat for desired reps.'),
('Barbell Curl',1,'While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out.'),
('Barbell Curl',2,'Continue the movement until your biceps are fully contracted and the bar is at shoulder level.'),
('Barbell Curl',3,'Hold the contracted position for a second and squeeze the biceps hard.'),
('Barbell Curl',4,'Slowly bring the weight back down to the starting position.'),
('Barbell Curtsy Deficit Lunge',1,'Stand on a platform, barbell on your back, feet hip-width apart.'),
('Barbell Curtsy Deficit Lunge',2,'Step back, lowering knee toward floor, keeping chest upright and core engaged.'),
('Barbell Curtsy Deficit Lunge',3,'Push through front foot, return to start, keeping bar stable throughout.'),
('Barbell Curtsy Lunge',1,'Place the barbell on your back'),
('Barbell Curtsy Lunge',2,'Step your foot back and around while simultaneously bringing the weight down.'),
('Barbell Curtsy Lunge',3,'Return to start and repeat on other leg.'),
('Barbell Deadlift',1,'Stand with your mid-foot under the bar and grip the bar with your hands, about a shoulder width apart.'),
('Barbell Deadlift',2,'Bend your knees, then lift the bar by straightening your back. It is important to keep your back straight.'),
('Barbell Deadlift',3,'Stand to your full height and hold.'),
('Barbell Deadlift',4,'Lower the bar to the floor by bending your knees and keeping your back straight.'),
('Barbell Deficit Conventional Deadlift',1,'Stand with your mid-foot under the bar, feet should be on a plate or elevated platform, and grip the bar with your hands, about a shoulder width apart.'),
('Barbell Deficit Conventional Deadlift',2,'Bend your knees, then lift the bar by straightening your back. It is important to keep your back straight.'),
('Barbell Deficit Conventional Deadlift',3,'Stand to your full height and hold.'),
('Barbell Deficit Conventional Deadlift',4,'Lower the bar to the floor by bending your knees and keeping your back straight.'),
('Barbell Deficit Lunge',1,'Stand on a platform, bar on your back, feet hip-width apart.'),
('Barbell Deficit Lunge',2,'Step back, lowering knee toward floor, keeping chest upright and core engaged.'),
('Barbell Deficit Lunge',3,'Push through front foot, return to start, keeping bar stable throughout.'),
('Barbell Drag Curl',1,'Grab a barbell with an underhand grip.'),
('Barbell Drag Curl',2,'Pull your elbows straight back and let the bar drag against your upper body (or very close to it).'),
('Barbell Feet Elevated Figure Four Glute Bridge',1,'Start by lying flat on your back with your feet resting on top of a box, the barbell placed over your hips, and cross one leg over the other.'),
('Barbell Feet Elevated Figure Four Glute Bridge',2,'Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box.'),
('Barbell Feet Elevated Figure Four Glute Bridge',3,'Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.'),
('Barbell Feet Elevated Glute Bridge',1,'Start by lying flat on your back with your feet resting on top of a box, the barbell placed over your hips.'),
('Barbell Feet Elevated Glute Bridge',2,'Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box.'),
('Barbell Feet Elevated Glute Bridge',3,'Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.'),
('Barbell Feet Elevated Single Leg Glute Bridge',1,'Start by lying flat on your back with your feet resting on top of a box, the barbell placed over your hips. Raise one leg up and off the box.'),
('Barbell Feet Elevated Single Leg Glute Bridge',2,'Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box.'),
('Barbell Feet Elevated Single Leg Glute Bridge',3,'Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.'),
('Barbell Feet Elevated Staggered Glute Bridge',1,'Start by lying flat on your back with your feet resting on top of a box, the barbell placed over your hips. Place one foot about 6-9 inches in front of the other.'),
('Barbell Feet Elevated Staggered Glute Bridge',2,'Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box.'),
('Barbell Feet Elevated Staggered Glute Bridge',3,'Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.'),
('Barbell Figure Four Heels Elevated Hip Thrust',1,'Put your shoulder blades on a bench and cross one leg over the other. Put one foot on a low box or plate.'),
('Barbell Figure Four Heels Elevated Hip Thrust',2,'Start with your hips up.'),
('Barbell Figure Four Heels Elevated Hip Thrust',3,'Drop your hips and then push your hips up toward the ceiling.'),
('Barbell Figure Four Hip Thrust',1,'Put your shoulder blades on a bench and cross one leg over the other.'),
('Barbell Figure Four Hip Thrust',2,'Start with your hips up.'),
('Barbell Figure Four Hip Thrust',3,'Drop your hips and then push your hips up toward the ceiling.'),
('Barbell Floor Press',1,'Un-rack the bar and break at the elbows and shoulders.'),
('Barbell Floor Press',2,'Bring your elbows to the floor, rest for a second to remove all the momentum from the rep, then press to a lockout.'),
('Barbell Front Rack Deficit Lunge',1,'Stand on a platform, barbell in front rack, feet hip-width apart.'),
('Barbell Front Rack Deficit Lunge',2,'Step back, lowering knee toward floor, keeping chest upright and core engaged.'),
('Barbell Front Rack Deficit Lunge',3,'Push through front foot, return to start, keeping bar stable throughout.'),
('Barbell Front Rack Step Up Knee Drive',1,'Hold barbell in front rack position and place one foot on the platform.'),
('Barbell Front Rack Step Up Knee Drive',2,'Drive through the front heel to step up, keeping chest tall and core braced.'),
('Barbell Front Rack Step Up Knee Drive',3,'Lift trailing knee high at the top, then step down slowly with control.'),
('Barbell Front Raise',1,'Stand tall with an overhand grip on the barbell. Raise your arms until your fists are around eye level.'),
('Barbell Front Raise',2,'Return to the start under control. This exercise is prone to using momentum when you begin to fatigue.'),
('Barbell Front Squat Bodybuilding',1,'Measure your shoulders against the bar to make sure you\'re even. Throw your shoulders under the bar. The bar should be digging into your neck slightly.'),
('Barbell Front Squat Bodybuilding',2,'Make sure to push your elbows up to the ceiling for the entire rep. To make sure you don\'t get too pitched forward.'),
('Barbell Front Squat Bodybuilding',3,'Use the squat stance you would use for a back or goblet squat. Push your hips back to initiate the squat. Break at the knees until you hit parallel depth.'),
('Barbell Front Squat Bodybuilding',4,'Squat back up to a standing position.'),
('Barbell Front Squat Olympic',1,'Measure your hands by the markings on the bar to make sure you\'re even. Then throw your elbows underneath the bar.'),
('Barbell Front Squat Olympic',2,'The bar should be set so high on your shoulders it digs into your neck a bit. Make sure to push your elbows up to the ceiling for the entire rep. To make sure you don\'t get too pitched forward.'),
('Barbell Front Squat Olympic',3,'Use the squat stance you would use for a back or goblet squat. Push your hips back to initiate the squat. Break at the knees until you hit parallel depth.'),
('Barbell Front Squat Olympic',4,'Squat back up to a standing position.'),
('Barbell Front Squat With Straps',1,'Measure your shoulders against the bar to make sure you\'re even. Wrap a pair of lifting straps around the bar. Hold the ends of the straps. Throw your shoulders under the bar. The bar should be digging into your neck slightly.'),
('Barbell Front Squat With Straps',2,'Make sure to push your elbows up to the ceiling for the entire rep. To make sure you don\'t get too pitched forward.'),
('Barbell Front Squat With Straps',3,'Use the squat stance you would use for a back or goblet squat. Push your hips back to initiate the squat. Break at the knees until you hit parallel depth.'),
('Barbell Front Squat With Straps',4,'Squat back up to a standing position.'),
('Barbell Full Front Raise',1,'Stand tall with an overhand grip on the barbell. Raise your arms until your fists are pointed toward the ceiling.'),
('Barbell Full Front Raise',2,'Return to the start under control. This exercise is prone to using momentum when you begin to fatigue.'),
('Barbell Glute Bridge',1,'Lie on your back on the floor with your knees bent and your feet flat on the ground. Place a barbell across your hips and grasp it with both hands.'),
('Barbell Glute Bridge',2,'Keeping your arms straight, push through your heels to lift your hips off the ground and raise the barbell.'),
('Barbell Glute Bridge',3,'Hold the bridge position for a moment, then slowly lower your hips back to the starting position.'),
('Barbell Guillotine High Incline Bench Press',1,'Set bench to high incline and grip bar slightly wider than shoulders.'),
('Barbell Guillotine High Incline Bench Press',2,'Lower bar slowly toward upper chest or neck with elbows flared.'),
('Barbell Guillotine High Incline Bench Press',3,'Press bar upward until arms fully extend without locking elbows.'),
('Barbell Guillotine Incline Bench Press',1,'Set bench to moderate incline and grip bar slightly wider than shoulders.'),
('Barbell Guillotine Incline Bench Press',2,'Lower bar toward upper chest or neck, keeping elbows out wide.'),
('Barbell Guillotine Incline Bench Press',3,'Press bar back up in a straight line over shoulders.'),
('Barbell Hang Clean And Press',1,'Hold bar just above knees with slight bend in hips and knees.'),
('Barbell Hang Clean And Press',2,'Explosively pull bar to shoulders, catching it in a partial squat.'),
('Barbell Hang Clean And Press',3,'Stand tall and press bar overhead until arms are fully extended.'),
('Barbell Heels Elevated Hip Thrust',1,'Sit on the ground with a bench behind you. Place both feet on a plate or low box. Have the barbell over your legs just above your hips.'),
('Barbell Heels Elevated Hip Thrust',2,'Lean back against the bench so that your shoulders are resting upon it, stretch your arms out to either side using the bench as support.'),
('Barbell Heels Elevated Hip Thrust',3,'Raise the weight by driving through your feet and extending your hips upwards. Support the weight with your shoulders and feet.'),
('Barbell Heels Elevated Hip Thrust',4,'Slowly extend as far as you can, and then slowly return to the starting position.'),
('Barbell Heels Up Back Squat',1,'Stand with your feet shoulder-width apart and your heels on a plate or low step.'),
('Barbell Heels Up Back Squat',2,'Bend your knees and lower your body into a squat position.'),
('Barbell Heels Up Back Squat',3,'Push through your heels to return to the starting position.'),
('Barbell Heels Up Front Squat',1,'Stand with your feet shoulder-width apart and feet on a plate. Place the bar in a front rack position.'),
('Barbell Heels Up Front Squat',2,'Bend your knees and lower your body into a squat position, keeping your heels raised off the ground.'),
('Barbell Heels Up Front Squat',3,'Push through your heels to return to the starting position.'),
('Barbell High Bar Good Morning',1,'Place the bar on your traps. You may need a pad so the bar doesn\'t dig into your cervical spine.'),
('Barbell High Bar Good Morning',2,'Push your hips straight back. Your knees should stay MOSTLY extended (think soft knees). Also make sure to'),
('Barbell High Bar Good Morning',3,'Look for what feels like a stretch in your hamstrings. The stretch feeling means you\'re likely nearing the end of your Range of Motion without rounding your spine.'),
('Barbell High Bar Good Morning',4,'When you feel the stretch push your hips forward until you\'re in a standing position.'),
('Barbell High Bar Squat',1,'Place the bar on top of your traps.'),
('Barbell High Bar Squat',2,'Push your hips back and break at the knees. Push your elbows forward to keep yourself from getting pitched too far forward.'),
('Barbell High Bar Squat',3,'Aim to get your hamstrings to parallel with the floor.'),
('Barbell High Bar Squat',4,'Push your heels into the floor and squat back to a standing position.'),
('Barbell High Incline Bench Press',1,'Position the bench between 45 and 60 degrees.'),
('Barbell High Incline Bench Press',2,'Lay flat on the bench with your feet on the ground. With straight arms unrack the bar.'),
('Barbell High Incline Bench Press',3,'Lower the bar to your mid chest'),
('Barbell High Incline Bench Press',4,'Raise the bar (slowly and controlled) until you\'ve locked your elbows.'),
('Barbell High Pull',1,'Stand with feet hip-width apart, grip the barbell slightly wider than shoulder-width, and keep your back straight.'),
('Barbell High Pull',2,'Drive through your legs, extending your hips, knees, and ankles explosively while pulling the barbell upward.'),
('Barbell High Pull',3,'As the bar rises, pull it close to your body, leading with your elbows until it reaches chest level.'),
('Barbell Hip Thrust',1,'Sit on the ground with a bench behind you. Have the barbell over your legs just above your hips.'),
('Barbell Hip Thrust',2,'Lean back against the bench so that your shoulders are resting upon it, stretch your arms out to either side using the bench as support.'),
('Barbell Hip Thrust',3,'Raise the weight by driving through your feet and extending your hips upwards. Support the weight with your shoulders and feet.'),
('Barbell Hip Thrust',4,'Slowly extend as far as you can, and then slowly return to the starting position.'),
('Barbell Hooklying Bench Press',1,'Start in a bench press position with your feet planted on the bench and knees bent.'),
('Barbell Hooklying Bench Press',2,'Grasp the barbell with an overhand grip, positioning your hands slightly wider than shoulder-width apart.'),
('Barbell Hooklying Bench Press',3,'Lift the barbell off the rack and lower it to your chest, keeping your elbows close to your sides.'),
('Barbell Hooklying Bench Press',4,'Push the barbell back up to the starting position, fully extending your arms.'),
('Barbell Incline Bench Press',1,'Position the bench between 30 and 45 degrees.'),
('Barbell Incline Bench Press',2,'Lay flat on the bench with your feet on the ground. With straight arms unrack the bar.'),
('Barbell Incline Bench Press',3,'Lower the bar to your mid chest'),
('Barbell Incline Bench Press',4,'Raise the bar (slowly and controlled) until you\'ve locked your elbows.'),
('Barbell J M Press',1,'Lie flat on bench and grip bar slightly narrower than shoulder-width.'),
('Barbell J M Press',2,'Lower bar toward upper chest by bending elbows forward, not flaring out.'),
('Barbell J M Press',3,'Extend elbows to press bar back to starting position above chest.'),
('Barbell Jefferson Deadlift',1,'Stand centered over the barbell, feet shoulder-width apart.'),
('Barbell Jefferson Deadlift',2,'Grip the bar with both hands, one in front, one behind.'),
('Barbell Jefferson Deadlift',3,'Lift by driving through your heels, keeping your back straight, then lower slowly.'),
('Barbell Kickstand Squat',1,'Stand with feet hip-width apart, one foot slightly behind. Bar on your back.'),
('Barbell Kickstand Squat',2,'Lower into a squat, keeping weight on front heel.'),
('Barbell Kickstand Squat',3,'Return to standing, engaging glutes and core.'),
('Barbell Landmine Row',1,'Position a barbell in a landmine or corner of a room and stand facing it with your feet shoulder-width apart.'),
('Barbell Landmine Row',2,'Grasp the end of the barbell with a neutral grip, keeping your arms straight and your shoulders relaxed.'),
('Barbell Landmine Row',3,'Bend at the hips and knees to lower your torso until it is almost parallel to the ground.'),
('Barbell Landmine Row',4,'Pull the barbell towards your chest, squeezing your shoulder blades together as you row the weight up.'),
('Barbell Landmine Side Bend',1,'Stand straight and hold the end of the Barbell'),
('Barbell Landmine Side Bend',2,'Keep your hips and shoulders facing forward, bend to one side slowly'),
('Barbell Landmine Side Bend',3,'Return to the upright position.'),
('Barbell Landmine Side Bend',4,'Switch hands and repeat.'),
('Barbell Landmine Sissy Squat',1,'Hold the bar in a goblet position.'),
('Barbell Landmine Sissy Squat',2,'Stand tall, push your knees forward until your calves touch your hamstrings.'),
('Barbell Landmine Sissy Squat',3,'Make sure to keep your hips extended.'),
('Barbell Larsen Bench Press',1,'Start in a bench press position with your legs elevated. Try to keep your knees with a slight bend in them.'),
('Barbell Larsen Bench Press',2,'Unrack the bar then initiate the rep.'),
('Barbell Larsen Bench Press',3,'Bring the bar to your torso and tap your ribcage before pressing back to the ceiling.'),
('Barbell Lateral Lunge',1,'Stand with your feet shoulder-width apart and hold a barbell at your shoulders with an overhand grip.'),
('Barbell Lateral Lunge',2,'Step out to the side with your right foot and bend your right knee to lower your body until your right thigh is parallel to the ground.'),
('Barbell Lateral Lunge',3,'Push off your right foot to return to the starting position.'),
('Barbell Lateral Lunge',4,'Repeat on the opposite side by stepping out with your left foot.'),
('Barbell Laying Triceps Extensions',1,'Lay on a flat bench while holding a barbell with a shoulder-width grip.'),
('Barbell Laying Triceps Extensions',2,'Fully extend your elbows until the barbell is directly over your chest.'),
('Barbell Laying Triceps Extensions',3,'Begin to flex your elbows and allow the barbell to nearly touch your forehead.'),
('Barbell Laying Triceps Extensions',4,'Extend your elbows back to the starting position and repeat.'),
('Barbell Long Landmine Row',1,'Position a barbell in a landmine or corner of a room and stand facing it with your feet shoulder-width apart.'),
('Barbell Long Landmine Row',2,'Grasp the end of the barbell with an overhand grip, keeping your arms straight and your shoulders relaxed.'),
('Barbell Long Landmine Row',3,'Bend at the hips and knees to lower your torso until it is almost parallel to the ground.'),
('Barbell Long Landmine Row',4,'Pull the barbell towards your chest, squeezing your shoulder blades together as you row the weight up.'),
('Barbell Low Bar Good Morning',1,'Place the bar between your traps and rear delts. Pull your shoulder blades back to give the bar a shelf to sit on.'),
('Barbell Low Bar Good Morning',2,'Push your hips back until you feel a stretch in your hamstrings. This means you\'re nearing the end of your Range of Motion with out rounding your spine.'),
('Barbell Low Bar Good Morning',3,'When you feel the stretch push your hips forward until you\'e in a standing position.'),
('Barbell Low Bar Squat',1,'Pull your shoulder blades back really hard and place the bar on your posterior delts.'),
('Barbell Low Bar Squat',2,'Push your hips back and break at the knees to initiate the squat.'),
('Barbell Low Bar Squat',3,'Aim to get your hamstrings to parallel with the ground. Push your heels into the floor and squat back up to a standing position.'),
('Barbell Meadows Row',1,'Position a barbell in a landmine or corner of a room and stand facing sideways with a staggered stance and your feet shoulder-width apart.'),
('Barbell Meadows Row',2,'Grasp the end of the barbell with an overhand grip, keeping your arms straight and your shoulders relaxed.'),
('Barbell Meadows Row',3,'Bend at the hips and knees to lower your torso until it is almost parallel to the ground.'),
('Barbell Meadows Row',4,'Pull the barbell towards your chest, squeezing your shoulder blades together as you row the weight up.'),
('Barbell Meadows Row',5,'*Named after the late John Meadows'),
('Barbell Muscle Snatch',1,'Stand with feet hip-width apart, grip the barbell with a wide overhand grip, and keep your back straight and core engaged.'),
('Barbell Muscle Snatch',2,'Lift the barbell by explosively extending your hips, knees, and ankles while keeping the bar close to your body.'),
('Barbell Muscle Snatch',3,'As the bar reaches chest level, rotate your wrists and elbows up and back, transitioning into an overhead press.'),
('Barbell Muscle Snatch',4,'Fully extend your arms overhead, stabilize the bar, then lower it back to the starting position with control.'),
('Barbell Overhead Press',1,'Take a roughly shoulder width grip. There should be a straight line from your elbow to fist (vertical forearms).'),
('Barbell Overhead Press',2,'Pull your chin back and press the weight toward the ceiling by extending at the elbow joint and flexing at the shoulder joint.'),
('Barbell Overhead Press',3,'Press until your elbows are extended and push your head forward slightly.'),
('Barbell Overhead Press',4,'Return to the start position with control. Pulling your chin back to allow the bar to pass your face safely.'),
('Barbell Overhead Tricep Extension',1,'Be careful getting the bar into place overhead. Push your elbows forward while keeping your elbows tucked in.'),
('Barbell Overhead Tricep Extension',2,'Look for what feels like a stretch in your triceps. Extend your elbows until your fists are pointed at the ceiling.'),
('Barbell Pause Box Squat',1,'Stand in front of a box or bench with your feet shoulder-width apart and a barbell resting on your upper back.'),
('Barbell Pause Box Squat',2,'Lower your body into a squat position, sitting back onto the box and pausing for a moment before standing back up.'),
('Barbell Pause Box Squat',3,'Push through your heels to return to the standing position.'),
('Barbell Pause Squat',1,'Stand with your feet shoulder-width apart and a barbell resting on your upper back.'),
('Barbell Pause Squat',2,'Lower your body into a squat position, pausing for a moment at the bottom of the movement before standing back up.'),
('Barbell Pause Squat',3,'Push through your heels to return to the standing position.'),
('Barbell Power Snatch',1,'Stand with feet hip-width apart, barbell over midfoot. Grip the bar wide (outside shoulders), hook grip recommended.'),
('Barbell Power Snatch',2,'Keep chest up, back straight, and drive through heels to lift the bar off the ground, keeping it close to your body.'),
('Barbell Power Snatch',3,'As the bar reaches mid-thigh, explode upwards by extending hips, knees, and ankles, shrugging shoulders and pulling the bar high.'),
('Barbell Power Snatch',4,'Drop under the bar slightly, catching it overhead with arms locked out. Stand up fully to complete the lift.'),
('Barbell Pronated Pendlay Row',1,'Start hinged forward with a flat back and the plates resting on the floor. Make sure your elbows are fully extended.'),
('Barbell Pronated Pendlay Row',2,'Pull the bar to your sternum.'),
('Barbell Pronated Pendlay Row',3,'Return the plates back to the floor and let the bar come to a full dead stop.'),
('Barbell Pronated Pendlay Row',4,'Then initiate the next rep.'),
('Barbell Pronated Row',1,'Grab the barbell with an overhand grip. Hinge forward while keeping your back flat until your torso is about parallel with the ground.'),
('Barbell Pronated Row',2,'Let your arms hang freely.'),
('Barbell Pronated Row',3,'Pull the bar to your torso while tucking your elbows in slightly.'),
('Barbell Pronated Row',4,'Extend your elbows fully before initiating the next rep.'),
('Barbell Pullover',1,'Lie flat on bench holding barbell above chest with slight elbow bend.'),
('Barbell Pullover',2,'Lower bar in an arc behind head until you feel a deep stretch.'),
('Barbell Pullover',3,'Pull bar back over chest using lats and triceps under control.'),
('Barbell Quad Stomp',1,'Have the barbell in a high bar position and place your foot on a plate or a low box.'),
('Barbell Quad Stomp',2,'Put all of your weight on your front foot and lean forward.'),
('Barbell Quad Stomp',3,'Lower until your calves touch your hamstrings and then extend back up.'),
('Barbell Rack Pull',1,'Set barbell just below knee height in rack and stand hip-width apart.'),
('Barbell Rack Pull',2,'Hinge at hips, grip bar firmly, and keep back flat.'),
('Barbell Rack Pull',3,'Drive hips forward and stand tall, locking out at the top.'),
('Barbell Reverse Curl',1,'Take a double overhand grip that\'s about shoulder width. Flex your elbows while keeping your elbows tucked in. Try not to let them flare out.'),
('Barbell Reverse Curl',2,'Curl until your forearm presses into your bicep. Then fully extend your elbows at the bottom of each rep.'),
('Barbell Reverse Deadlift',1,'Start by standing with your feet about hip-width apart, with your toes pointed slightly outward.'),
('Barbell Reverse Deadlift',2,'Place a barbell on the floor behind you, with the weight plates on either side.'),
('Barbell Reverse Deadlift',3,'Bend down and grab the barbell with an overhand grip, your hands slightly wider than shoulder-width apart. Keep your back straight and your shoulders down as you grip the bar.'),
('Barbell Reverse Deadlift',4,'Stand up straight, lifting the barbell off the ground and pulling it toward your hips. Keep your elbows close to your body and your shoulders down as you do this.'),
('Barbell Reverse Grip Bench Press',1,'Lay flat on the bench with your feet on the ground. With straight arms unrack the bar with a reverse grip.'),
('Barbell Reverse Grip Bench Press',2,'Lower the bar to your lower chest'),
('Barbell Reverse Grip Bench Press',3,'Raise the bar until you\'ve locked your elbows.'),
('Barbell Reverse Lunge',1,'Start by standing with your feet about hip-width apart, with a barbell on your shoulders. Your feet should be slightly pointed outward, and your shoulders should be down and relaxed.'),
('Barbell Reverse Lunge',2,'Step backward with one foot, lowering your body until your front thigh is parallel to the ground and your back knee is hovering just above the ground.'),
('Barbell Reverse Lunge',3,'Push off your back foot, returning to the starting position.'),
('Barbell Roll Outs',1,'Hold the Barbell with both hands and kneel on the floor with your feet up'),
('Barbell Roll Outs',2,'Slowly roll the Barbell straight forward, stretching your body into a straight position.'),
('Barbell Roll Outs',3,'After a pause at the stretched position, start pulling yourself back to the starting position. This should be a slow and controlled movement.'),
('Barbell Romanian Deadlift',1,'Take a shoulder width, double overhand or mixed grip.'),
('Barbell Romanian Deadlift',2,'Push your hips back while leaving your knees mostly extended. Look for a stretch in your hamstrings.'),
('Barbell Romanian Deadlift',3,'When you feel the stretch, push your hips forward until you\'re back in a standing position.'),
('Barbell Seated Calf Raise',1,'Start by sitting on a bench with a barbell resting on your knees. Your feet should be flat on the ground, about hip-width apart.'),
('Barbell Seated Calf Raise',2,'Place your hands on the barbell for support, and lift your heels off the ground.'),
('Barbell Seated Calf Raise',3,'Hold this position for a moment, then slowly lower your heels back to the ground.'),
('Barbell Seated Full Front Raise',1,'Sit on an incline bench with an overhand grip on the barbell. Raise your arms until your fists are pointed toward the ceiling.'),
('Barbell Seated Full Front Raise',2,'Return to the start under control. This exercise is prone to using momentum when you begin to fatigue.'),
('Barbell Shoulder Extension',1,'Hold barbell behind hips with straight arms and palms facing back.'),
('Barbell Shoulder Extension',2,'Keeping arms straight, lift bar slightly backward until lats engage.'),
('Barbell Shoulder Extension',3,'Lower bar slowly to starting position while maintaining tension.'),
('Barbell Shrug',1,'Start by standing with your feet about hip-width apart, with a barbell in front of you.'),
('Barbell Shrug',2,'Bend down and grab the barbell with an overhand grip, your hands slightly wider than shoulder-width apart. Keep your back straight and your shoulders down as you grip the bar.'),
('Barbell Shrug',3,'Stand up straight, lifting the barbell off the ground and pulling it toward your hips. Keep your elbows close to your body and your shoulders down as you do this.'),
('Barbell Shrug',4,'Once the barbell is at your hips, raise your shoulders as high as you can, holding the position for a moment.'),
('Barbell Side Step Up',1,'Start by standing with your feet about hip-width apart, with a barbell on your shoulders. Your feet should be slightly pointed outward, and your shoulders should be down and relaxed.'),
('Barbell Side Step Up',2,'Place a step or box beside you, and step up onto it with one foot. Your other foot should remain on the ground.'),
('Barbell Side Step Up',3,'Push off your grounded foot, raising your body up onto the step.'),
('Barbell Side Step Up',4,'Step back down with the same foot, returning to the starting position.'),
('Barbell Silverback Shrug',1,'Stand with your feet shoulder width apart holding the Barbell with both hands in front just past shoulder width.'),
('Barbell Silverback Shrug',2,'Bend forward at the hips with a slight bend in your knees, keeping your back straight.'),
('Barbell Silverback Shrug',3,'Engage your shoulder blades, as if you are trying to touch them together.'),
('Barbell Silverback Shrug',4,'Release the shrug.'),
('Barbell Single Leg Deadlift',1,'Start by pushing your hips straight back and extending your non-working leg behind you. It is ok to touch your other foot back to the ground each rep.'),
('Barbell Single Leg Deadlift',2,'Leave your knee mostly extended. Look for a stretch in your hamstring. When you feel the stretch, push your hips forward until you\'re back in a standing position.'),
('Barbell Single Leg Heels Elevated Hip Thrust',1,'Start by lying on a bench with your foot on a plate or low box and a barbell on your hips.'),
('Barbell Single Leg Heels Elevated Hip Thrust',2,'Lift one leg off the ground and engage your glutes to raise your hips up towards the ceiling.'),
('Barbell Single Leg Heels Elevated Hip Thrust',3,'From this starting position, slowly lower your hips back down to the starting position.'),
('Barbell Single Leg Hip Thrust',1,'Start by lying on a bench with your foot on the ground and a barbell on your hips.'),
('Barbell Single Leg Hip Thrust',2,'Lift one leg off the ground and engage your glutes to raise your hips up towards the ceiling.'),
('Barbell Single Leg Hip Thrust',3,'From this starting position, slowly lower your hips back down to the starting position.'),
('Barbell Situp',1,'Hold the bar with a slightly wider than shoulder width grip. Push the bar up toward the ceiling and maintain that elbow extension.'),
('Barbell Situp',2,'Flex your abs and sit-up. Aim to get your torso vertical while maintaining the barbell overhead.'),
('Barbell Skullcrusher',1,'Take a shoulder width grip. Break at the elbows. Try to keep your elbows tucked in. Don\'t let them flare out.'),
('Barbell Skullcrusher',2,'Stop the bar a few inches from your forehead and extend your elbows back up.'),
('Barbell Snatch',1,'Stand with feet shoulder-width apart, barbell over midfoot. Grip the bar wide with an overhand grip, chest up, and back straight.'),
('Barbell Snatch',2,'Lift the bar by driving through your legs, keeping it close to your body. Extend your hips and knees while maintaining a straight back.'),
('Barbell Snatch',3,'Explosively extend your hips, knees, and ankles while shrugging your shoulders. Pull yourself under the bar as it moves upward.'),
('Barbell Snatch',4,'Drop into a deep squat while locking the bar overhead. Stabilize, then stand up fully to complete the lift.'),
('Barbell Snatch Grip Deadlift',1,'Start by standing with your feet about hip-width apart, with your toes pointed slightly outward.'),
('Barbell Snatch Grip Deadlift',2,'Place a barbell on the floor in front of you, with the weight plates on either side. Make sure that the bar is directly in line with your feet.'),
('Barbell Snatch Grip Deadlift',3,'Bend down and grab the barbell with an overhand grip, your hands much wider than shoulder-width apart. Keep your back straight and your shoulders down as you grip the bar.'),
('Barbell Snatch Grip Deadlift',4,'Stand up straight, lifting the barbell off the ground and pulling it toward your hips. Keep your elbows close to your body and your shoulders down as you do this.'),
('Barbell Snatch Grip Deadlift',5,'Slowly lower the barbell back to the ground, making sure to keep your back straight and your shoulders down throughout the movement.'),
('Barbell Snatch Grip High Pull',1,'Stand with feet hip-width apart, gripping the barbell with a wide (snatch-width) grip. Keep your back straight, chest up, and bar close to your body.'),
('Barbell Snatch Grip High Pull',2,'Drive through your legs, extending your hips, knees, and ankles while pulling the barbell up explosively.'),
('Barbell Snatch Grip High Pull',3,'Shrug your shoulders forcefully and pull the bar as high as possible, keeping elbows above the bar.'),
('Barbell Snatch Grip High Pull',4,'Lower the bar back to the starting position in a controlled manner and reset for the next rep.'),
('Barbell Snatch Grip Romanian Deadlift',1,'Start by standing with your feet about hip-width apart. The bar should be in a rack or box so it\'s lifted off the ground.'),
('Barbell Snatch Grip Romanian Deadlift',2,'Grab the barbell with an overhand grip, your hands should be much wider than shoulder-width apart.'),
('Barbell Snatch Grip Romanian Deadlift',3,'Hing forward at the hips keeping your knees mostly extended. Hinge until you feel a stretch in your hamstrings.'),
('Barbell Snatch Grip Romanian Deadlift',4,'When you feel the stretch, push your hips forward until you are back in a standing position.'),
('Barbell Spinal Jefferson Curl',1,'Stand on a platform holding barbell in front with feet hip-width apart.'),
('Barbell Spinal Jefferson Curl',2,'Slowly roll down through spine one vertebra at a time, reaching toward toes.'),
('Barbell Spinal Jefferson Curl',3,'Reverse the motion, rolling up through spine until standing tall again.'),
('Barbell Split Jerk',1,'Start with the barbell on your shoulders in a front rack position, feet hip-width apart. Slightly bend your knees and dip straight down.'),
('Barbell Split Jerk',2,'Explosively extend your legs and push the barbell upward, generating momentum with your legs.'),
('Barbell Split Jerk',3,'As the bar rises, quickly split your legs (one forward, one back) and drop under the bar, locking your arms overhead.'),
('Barbell Split Jerk',4,'Bring your front foot back, then your back foot forward to a stable standing position with the bar locked overhead.'),
('Barbell Split Squat',1,'Take a large step forward with one leg, and lower your body until your back knee nearly touches the ground. Your front knee should be bent at a 90-degree angle, and your back leg should be straight.'),
('Barbell Split Squat',2,'Push through the heel of your front foot to raise your body back to the starting position.'),
('Barbell Spoto Press',1,'Start on the bench with your shoulder blades pulled back.'),
('Barbell Spoto Press',2,'As you initiate the first rep, tuck your elbows slightly until the bar is a few inches off your chest.'),
('Barbell Spoto Press',3,'Pause just off your chest for 1-3 seconds. Then press explosively.'),
('Barbell Squat',1,'Stand with your feet shoulder-width apart. Maintain the natural arch in your back, squeezing your shoulder blades and raising your chest.'),
('Barbell Squat',2,'Grip the bar across your shoulders and support it on your upper back. Unwrack the bar by straightening your legs, and take a step back.'),
('Barbell Squat',3,'Bend your knees as you lower the weight without altering the form of your back until your hips are below your knees.'),
('Barbell Squat',4,'Raise the bar back to starting position, lift with your legs and exhale at the top.'),
('Barbell Staggered Deadlift',1,'Place one foot behind. You should only be on your toes on that back foot. Your front foot should be planted flat the entire time.'),
('Barbell Staggered Deadlift',2,'Bend your back knee and push your hips back. Look for a stretch in your front hamstring.'),
('Barbell Staggered Deadlift',3,'When you feel the stretch, push your hips forward again until you\'re back in a standing position.'),
('Barbell Step Up',1,'Begin by standing in front of a sturdy box or bench that is about knee-height, holding a barbell across your upper back and shoulders, using an overhand grip.'),
('Barbell Step Up',2,'Place your right foot on the box and push through the heel to lift your body up and onto the box.'),
('Barbell Step Up',3,'Step back down with your right foot.'),
('Barbell Step Up Balance',1,'Begin by standing in front of a sturdy box or bench that is about knee-height, holding a barbell across your upper back and shoulders, using an overhand grip.'),
('Barbell Step Up Balance',2,'Place your right foot on the box and push through the heel to lift your body up and onto the box, keeping your left foot off the ground.'),
('Barbell Step Up Balance',3,'Step back down with your right foot, lowering your left foot to the ground.'),
('Barbell Step Up Knee Drive',1,'Hold barbell on upper back and place one foot firmly on platform.'),
('Barbell Step Up Knee Drive',2,'Drive through front heel to step up, keeping torso tall and balanced.'),
('Barbell Step Up Knee Drive',3,'Lift trailing knee high at the top, then step down slowly with control.'),
('Barbell Stiff Leg Deadlifts',1,'Stand with a barbell at your shins with your feet shoulder width apart.'),
('Barbell Stiff Leg Deadlifts',2,'Bend forward at your hips and keep your knees as fully extended as possible.'),
('Barbell Stiff Leg Deadlifts',3,'Grab the barbell and then extend your hips while maintaining a straight back.'),
('Barbell Stiff Leg Deadlifts',4,'From the standing position, lower the weight in a controlled manner.'),
('Barbell Stiff Leg Deadlifts',5,'You can either lower the weight to the floor or before you touch the floor, depending on your mobility.'),
('Barbell Suitcase Carry',1,'Begin by standing with your feet hip-width apart with the bar on the ground at your side.'),
('Barbell Suitcase Carry',2,'Lift the bar to your side and walk for the allotted amount of time or distance.'),
('Barbell Suitcase Carry',3,'Set the bar down and switch sides.'),
('Barbell Suitcase Deadlift',1,'Begin by standing with your feet hip-width apart and holding a barbell at one side of your body, with your palms facing your thighs.'),
('Barbell Suitcase Deadlift',2,'Keeping your core engaged and your back straight, bend at the hips and knees to lower the barbell down towards the ground.'),
('Barbell Suitcase Deadlift',3,'As the barbell reaches the ground, use your legs and glutes to push through your heels and extend your hips and knees to raise your body back to the starting position.'),
('Barbell Suitcase Deadlift',4,'Repeat the movement for the desired number of reps, then switch sides and repeat the exercise with the barbell on the opposite side of your body.'),
('Barbell Sumo Deadlift',1,'Stance width can vary with a sumo DL. Some prefer toes near the plates. Others prefer a more narrow stance to get more drive off the floor.'),
('Barbell Sumo Deadlift',2,'Make sure your arms are inside your legs. The bar should be just over your mid-foot. Flatten your back and push your heels into the floor.'),
('Barbell Sumo Deadlift',3,'Try to extend your knees and hips simultaneously.'),
('Barbell Sumo Pause Deadlift',1,'Set up for a sumo deadlift, grip the barbell.'),
('Barbell Sumo Pause Deadlift',2,'Lift, pause at knee height.'),
('Barbell Sumo Pause Deadlift',3,'Hold briefly, then complete the lift; reset and repeat for desired reps.'),
('Barbell Supinated Pendlay Row',1,'Begin by standing in front of a barbell with your feet about hip-width apart and your palms facing towards your body.'),
('Barbell Supinated Pendlay Row',2,'Bend at the hips and knees to grab the barbell with a pronated (overhand) grip, positioning the barbell about an inch away from your shins.'),
('Barbell Supinated Pendlay Row',3,'Keeping your back straight and your core engaged, use your back muscles to lift the barbell straight up towards your chest.'),
('Barbell Supinated Pendlay Row',4,'As the barbell reaches your chest, rotate your wrists so that your palms are facing towards your body (supinated grip), and then lower the barbell back to the starting position.'),
('Barbell Supinated Row',1,'Begin by standing in front of a barbell with your feet about hip-width apart.'),
('Barbell Supinated Row',2,'Bend at the hips and knees to grab the barbell with a supinated (underhand) grip, positioning the barbell about an inch away from your shins.'),
('Barbell Supinated Row',3,'Keeping your back straight and your core engaged, use your back muscles to lift the barbell straight up towards your chest.'),
('Barbell Supinated Row',4,'As the barbell reaches your chest, pause briefly, and then lower the barbell back to the starting position.'),
('Barbell Tap Pause Squat',1,'Begin by standing in front of a sturdy box or bench that is about knee-height, holding a barbell across your upper back and shoulders, using an overhand grip.'),
('Barbell Tap Pause Squat',2,'Sit back and lower your body down until your glutes tap the top of the box, keeping your back straight and your core engaged.'),
('Barbell Tap Pause Squat',3,'Push through your heels to extend your hips and stand up, bringing your body back to the starting position.'),
('Barbell Thruster',1,'Hold the bar in a front rack position.'),
('Barbell Thruster',2,'Push your hips back and sink into a squat.'),
('Barbell Thruster',3,'Push through your heels and squat back up. Use the momentum you generate at the legs to push the bar over head.'),
('Barbell Thruster',4,'Let the bar return to the front rack position before starting the next rep.'),
('Barbell Toes Up Calf Raise',1,'Begin by standing on a raised surface (such as a step or box) with the balls of your feet on the edge of the surface and your heels hanging off. Hold a barbell across your upper back and shoulders, using an overhand grip.'),
('Barbell Toes Up Calf Raise',2,'Keeping your core engaged and your back straight, push through the balls of your feet to raise your heels up as high as you can.'),
('Barbell Toes Up Calf Raise',3,'Lower your heels back down to the starting position, allowing your calves to stretch.'),
('Barbell Tricep Guillotine Press',1,'Unrack the barbell. Break at the elbows and begin lowering the barbell.'),
