('Bodyweight Alternating Lateral Lunge',2,'Step right, lunge to side.'),
('Bodyweight Alternating Lateral Lunge',3,'Return, then lunge left.'),
('Bodyweight Alternating Reverse Lunges',1,'Stand with feet together.'),
('Bodyweight Alternating Reverse Lunges',2,'Step back with right foot.'),
('Bodyweight Alternating Reverse Lunges',3,'Return to starting position, then lunge with left foot.'),
('Bodyweight Assisted Chin Up',1,'Grasp the chin-up bar with an underhand grip, shoulder-width apart.'),
('Bodyweight Assisted Chin Up',2,'Place your feet on the ground, legs bent slightly.'),
