('Forearms Stretch Variation Three',2,'Rotate your arms and hands 180 degrees.'),
('Forearms Stretch Variation Three',3,'Hold at the peak of the stretch.'),
('Forearms Stretch Variation Three',4,'Return to starting position.'),
('Forearms Stretch Variation Two',1,'Place your hand against a wall, palms facing upward, with finger tips touching.'),
('Forearms Stretch Variation Two',2,'Slowly lean into your palm.'),
('Forearms Stretch Variation Two',3,'Hold at the peak of the stretch.'),
('Forearms Stretch Variation Two',4,'Return to starting position.'),
('Forward Arm Circle',1,'Hold your arms out to your sides.'),
('Forward Arm Circle',2,'Rotate your arms forward in small circles.'),
('Forward Lunges',1,'Step forward with one leg.'),
('Forward Lunges',2,'Lower your body until your rear knee nearly touches the ground.'),
('Forward Lunges',3,'Ensure you remain upright, and your front knee stay above the front foot.'),
('Forward Lunges',4,'Push off the floor with your front foot until you return to the starting position. Switch legs.'),
