('Mini-Band Clamshell',2,'Keep feet together, lift top knee upward.'),
('Mini-Band Clamshell',3,'Lower slowly without rotating hips backward.'),
('Monkey Pose',1,'Begin in a low lunge with your right foot forward and your left knee on the ground.'),
('Monkey Pose',2,'Slowly slide your left knee back while extending your right leg forward, keeping both legs straight.'),
('Monkey Pose',3,'Lower your body down to the ground, using your hands for support if needed.'),
('Monkey Pose',4,'Hold the pose for a few breaths, then switch sides and repeat.'),
('Mountain',1,'Stand tall with your feet hip-width apart and your arms at your sides.'),
('Mountain',2,'Press your feet into the ground and engage your leg muscles.'),
('Mountain',3,'Lift your chest and roll your shoulders back and down.'),
('Mountain',4,'Take a deep breath in, and as you exhale, release any tension in your body and relax your muscles.'),
('Narrow Pulldown',1,'Use the Straight Bar attachment.'),
('Narrow Pulldown',2,'Hold the attachment as you sit on the machine and put your legs under the leg pads.'),
('Narrow Pulldown',3,'Pull the bar to your clavicle, then raise back up until your arm are extended.'),
('Neutral Pulldown',1,'Use the V Bar attachment.'),
('Neutral Pulldown',2,'Hold the attachment as you sit on the machine and put your legs under the leg pads.'),
('Neutral Pulldown',3,'Pull the bar to your clavicle, then raise back up until your arm are extended.'),
('Nordic Hamstring Curl',1,'Go to your knees and ask someone to hold your ankles.'),
('Nordic Hamstring Curl',2,'Put your hands in front of you'),
('Nordic Hamstring Curl',3,'With a slight bend in your knees slowly bring your body to the ground (slower is better)'),
('Nordic Hamstring Curl',4,'Push up and reset to the starting position.'),
('Oblique Crunch',1,'Lie on your side, knees bent, hands behind head.'),
('Oblique Crunch',2,'Bring your elbow towards your knees and flex your obliques.'),
('Oblique Jackknife',1,'Lie on your side, legs straight, hand behind head.'),
('Oblique Jackknife',2,'Lift both legs and upper body simultaneously.'),
('Oblique Jackknife',3,'Squeeze obliques, then lower back down. Repeat on both sides.'),
('One Arm Cow Face Pose',1,'Sit on the floor with your legs extended in front of you.'),
('One Arm Cow Face Pose',2,'Bend your left knee and place your left foot on the floor, close to your right hip.'),
('One Arm Cow Face Pose',3,'Cross your right leg over your left leg, stacking your knees on top of each other.'),
('One Arm Cow Face Pose',4,'Bring your left arm up overhead, and bend your elbow so that your left hand reaches towards your upper back. Reach your right hand behind your back and try to clasp your left hand. Hold'),
('Parallel Bar Dips',1,'Grip bars with arms straight, shoulders above hands. Keep legs straight or bent.'),
('Parallel Bar Dips',2,'Lower slowly until elbows are at 90 degrees.'),
('Parallel Bar Dips',3,'Push back up to start position, extending arms fully.'),
('Pigeon Pose',1,'Extend your right leg behind you and place your right ankle on top of your left thigh, with your right knee pointing out to the side.'),
('Pigeon Pose',2,'Sitting up straight, use your hands to gently press down on your right knee while at the same time pulling your left buttock back.'),
('Pigeon Pose',3,'Hold for 5-10 deep breaths, then release and repeat on the other side.'),
('Pilates Back Rowing Seated Row',1,'Sit tall, legs extended, hold straps with arms forward.'),
('Pilates Back Rowing Seated Row',2,'Pull handles toward torso, squeezing shoulder blades together.'),
('Pilates Back Rowing Seated Row',3,'Keep chest lifted and spine neutral throughout.'),
('Pilates Back Rowing Seated Row',4,'Extend arms forward under control.'),
('Pilates Footwork First Position',1,'Lie on reformer, heels together, toes apart on footbar.'),
('Pilates Footwork First Position',2,'Press carriage out by extending legs evenly.'),
('Pilates Footwork First Position',3,'Keep pelvis stable and core engaged.'),
('Pilates Footwork First Position',4,'Bend knees to return with control.'),
('Pilates Hamtring Curls Prone',1,'Lie prone, attach straps to ankles, legs extended.'),
('Pilates Hamtring Curls Prone',2,'Bend knees, pulling heels toward glutes.'),
('Pilates Hamtring Curls Prone',3,'Keep hips pressed down and core engaged.'),
('Pilates Hamtring Curls Prone',4,'Extend legs slowly back to start.'),
('Pilates Scooter',1,'Stand beside reformer, one foot on carriage, one stable on floor.'),
('Pilates Scooter',2,'Press carriage back by extending moving leg.'),
('Pilates Short Spine',1,'Lie supine, feet in straps, legs extended upward.'),
('Pilates Short Spine',2,'Lift hips, rolling spine off carriage.'),
('Pilates Short Spine',3,'Bend knees, bringing heels toward glutes overhead.'),
('Pilates Short Spine',4,'Roll down slowly, extending legs to start.'),
('Pilates Single Arm Back Rowing Seated Row',1,'Sit tall, hold one strap, arm extended forward.'),
('Pilates Single Arm Back Rowing Seated Row',2,'Pull handle toward torso, squeezing shoulder blade.'),
('Pilates Single Arm Back Rowing Seated Row',3,'Keep torso stable without rotation.'),
('Pilates Single Arm Back Rowing Seated Row',4,'Extend arm forward under control.'),
('Pilates Single Arm Rotations Back Rowing Seated Row',1,'Sit tall, hold one strap, arm extended forward.'),
('Pilates Single Arm Rotations Back Rowing Seated Row',2,'Pull handle while rotating torso slightly.'),
('Pilates Single Arm Rotations Back Rowing Seated Row',3,'Keep hips stable and movement controlled.'),
('Pilates Single Arm Rotations Back Rowing Seated Row',4,'Return arm and torso to start.'),
('Pilates Single Leg Heel',1,'Lie on reformer, one heel on footbar, other leg extended.'),
('Pilates Single Leg Heel',2,'Press carriage out using working leg.'),
('Pilates Single Leg Heel',3,'Keep hips level and core engaged.'),
('Pilates Single Leg Heel',4,'Bend knee to return with control.'),
('Pilates Teaser Prep',1,'Lie supine, knees bent, arms reaching toward thighs.'),
('Pilates Teaser Prep',2,'Lift head, shoulders, and upper back off carriage.'),
('Pilates Teaser Prep',3,'Reach forward while maintaining core engagement.'),
('Pilates Teaser Prep',4,'Lower slowly back to starting position.'),
('Plank IYTW',1,'Start in a plank position. Hold one dumbbell.'),
('Plank IYTW',2,'Raise the dumbbell straight out in front of you (I), at a 45 degree angle (Y), out to the side (T), and then bend at the elbow while raising (W).'),
('Plank IYTW',3,'Going through IYTW counts as one rep.'),
('Plank IYTW',4,'Make sure to keep your hips stable. If you\'re unable to, try performing this exercise from the knees.'),
('Plate Alternating Deadstop Row',1,'Stand with your feet shoulder width apart. Hold each plate to the side of you.'),
('Plate Alternating Deadstop Row',2,'Bend forward at the hips bringing the plates to the floor while you slightly bend your knees, keeping your back straight.'),
('Plate Alternating Deadstop Row',3,'One at a time, lift the plate up. Return the plate to the floor and do the other side.'),
('Plate Bicep Curl',1,'Hold plate in both hands.'),
('Plate Bicep Curl',2,'Flex your elbows until the plate nears your chest.'),
('Plate Bicep Curl',3,'Extend your elbows until they are fully extended.'),
('Plate Car Driver',1,'Inhale and brace your abdominals'),
('Plate Car Driver',2,'Raise the arms vertically while keeping the elbows slightly bent'),
('Plate Car Driver',3,'Once the arms are parallel with the floor, rotate the plate clockwise and counterclockwise.'),
('Plate Car Driver',4,'Lower the plate back to the starting position.'),
('Plate Clean',1,'Stand with feet shoulder-width apart and the plate in front of the feet.'),
('Plate Clean',2,'Bend the knees and hips to pick up the plate, keeping the back straight and core engaged.'),
('Plate Clean',3,'Stand up while pulling the plate towards the chest.'),
('Plate Clean',4,'Keep shoulder level while keeping the elbows high and in front of the plate.'),
('Plate Clean And Press',1,'Stand with feet shoulder-width apart and the plate in front of the feet.'),
('Plate Clean And Press',2,'Bend the knees and hips to pick up the plate, keeping the back straight and core engaged.'),
('Plate Clean And Press',3,'Stand up, lock the hips and legs, and press the plate overhead with straight arms.'),
('Plate Clean And Press',4,'Lower the plate back to the starting position, keeping control of it, and repeat for desired reps.'),
('Plate Curl To Overhead Press',1,'Stand with feet shoulder-width apart and the plate in front of the torso, palms facing forward.'),
('Plate Curl To Overhead Press',2,'Curl the plate up to the front of the shoulder while keeping the elbows close to the body.'),
('Plate Curl To Overhead Press',3,'Rotate the palms to face forward and press the plate overhead, locking out the arms.'),
('Plate Curl To Overhead Press',4,'Lower the plate back to the starting position, keeping control of it, and repeat for desired reps.'),
('Plate Curl To Overhead Press To Tricep Extension',1,'Stand with feet shoulder-width apart and the plate in front of the torso, palms facing forward.'),
('Plate Curl To Overhead Press To Tricep Extension',2,'Curl the plate up to the front of the shoulder while keeping the elbows close to the body.'),
('Plate Curl To Overhead Press To Tricep Extension',3,'Rotate the palms to face forward and press the plate overhead, locking out the arms.'),
('Plate Curl To Overhead Press To Tricep Extension',4,'Lower the plate back behind the head to the starting position of a tricep extension.'),
('Plate Curl To Overhead Press To Tricep Extension',5,'Push the plate back up overhead, then lower it back to the starting position and repeat for desired reps.'),
('Plate Curtsy Lunge',1,'Stand with feet shoulder-width apart and the plate in front of the torso.'),
('Plate Curtsy Lunge',2,'Step back and across the body with the right foot, bending both legs to lower into a lunge position.'),
('Plate Curtsy Lunge',3,'Push through the front foot to return to the starting position.'),
('Plate Curtsy Lunge',4,'Repeat on the other side by stepping back and across with the left foot.'),
('Plate Curtsy Lunge',5,'Continue alternating sides for desired reps.'),
('Plate Deadlift',1,'Stand with feet hip-width apart, the plate in front of the feet, and the knees slightly bent.'),
('Plate Deadlift',2,'Bend the hips and knees to grip the plate with palms facing the body.'),
('Plate Deadlift',3,'Keeping the back straight, stand up while lifting the plate off the ground.'),
('Plate Deadlift',4,'Return the plate back to the starting position by bending the hips and knees, keeping control of the plate.'),
('Plate Deficit Lunge',1,'Stand on a plate with both feet.'),
('Plate Deficit Lunge',2,'Step back with one foot to the floor and let your back knee get close to or tap the floor.'),
('Plate Deficit Lunge',3,'Push through your front leg until both feet are back on the plate.'),
('Plate Deficit Pushup',1,'Start in a pushup position with both hands on a plate. This will extend your range of motion.'),
('Plate Deficit Pushup',2,'Break at the elbows and shoulders until your upper arm travels behind the body slightly.'),
('Plate Deficit Pushup',3,'Then press back into the original position.'),
('Plate Forward Lunge',1,'Stand with feet hip-width apart and the plate held in front of the torso.'),
('Plate Forward Lunge',2,'Take a step forward with one foot, bending the front knee to lower the hips into a lunge.'),
('Plate Forward Lunge',3,'Push through the front foot to return to the starting position.'),
('Plate Forward Lunge',4,'Repeat on the other side by stepping forward with the other foot.'),
('Plate Front Raise',1,'Stand with feet shoulder-width apart and the plate in front of the torso, palms facing the thighs.'),
('Plate Front Raise',2,'Keeping the elbows slightly bent, lift the plate up to the front of the body.'),
('Plate Front Raise',3,'Raise the plate up until the arms are fully extended, maintaining control of the plate.'),
('Plate Front Raise',4,'Lower the plate back to the starting position and repeat for desired reps.'),
('Plate Full Lateral Raise',1,'Stand tall holding two plates at your side.'),
('Plate Full Lateral Raise',2,'Lateral raise the plates to your side and continue until the plates are pointed at the ceiling.'),
('Plate Full Lateral Raise',3,'Let your shoulder joint naturally rotate. At the bottom you should have a neutral or overhand grip. By the time the plates are overhead, your palms should be facing forward.'),
('Plate Glute Bridge to Chest Press',1,'Lay flat on the ground with a plate on your chest.'),
('Plate Glute Bridge to Chest Press',2,'Push your hips up toward the ceiling and maintain that extended position.'),
('Plate Glute Bridge to Chest Press',3,'With your hips up, press the plate toward the ceiling.'),
('Plate Glute Bridge to Pullover',1,'Lay flat on the ground with a plate on your chest.'),
('Plate Glute Bridge to Pullover',2,'Push your hips up toward the ceiling and maintain that extended position.'),
('Plate Glute Bridge to Pullover',3,'Extend your elbows mostly, break at the shoulder joint while maintaining hip extension and the slight bend in your elbows.'),
('Plate Glute Bridge to Pullover',4,'Let the plate tap the floor (or get close) and then pull the plate back into the starting position.'),
('Plate Goblet Deficit Reverse Lunge',1,'Stand on a platform, Holding a plate to your chest, feet hip-width apart.'),
('Plate Goblet Deficit Reverse Lunge',2,'Step back, lowering knee toward floor, keeping chest upright and core engaged.'),
('Plate Goblet Deficit Reverse Lunge',3,'Push through front foot, return to start.'),
('Plate Good Morning',1,'Stand with feet hip-width apart, the plate held behind the neck and the knees slightly bent.'),
('Plate Good Morning',2,'Bend forward at the hips, keeping the back straight, until the torso is parallel to the floor.'),
('Plate Good Morning',3,'Push through the hips to return to the starting position.'),
('Plate Good Morning Anterior',1,'Stand with feet hip-width apart, the plate held in front of you, and the knees slightly bent.'),
('Plate Good Morning Anterior',2,'Bend forward at the hips, keeping the back straight, until the torso is parallel to the floor.'),
('Plate Good Morning Anterior',3,'Push through the hips to return to the starting position.'),
('Plate Halo',1,'Stand with feet shoulder-width apart and the plate held in front of your face with both hands, palms facing each other.'),
('Plate Halo',2,'Rotate the plate around the head, keeping the arms extended and moving the plate in a circular motion.'),
('Plate Halo',3,'Complete one full circle, then reverse the direction to complete another circle.'),
('Plate Hip Abduction',1,'Stand tall holding plate against outer thigh or anchored between legs.'),
('Plate Hip Abduction',2,'Lift leg outward to the side while keeping torso still and toes forward.'),
('Plate Hip Abduction',3,'Lower slowly under control, maintaining tension on outer hip.'),
('Plate Hollow Hold',1,'Lay flat on the ground with your arms extended over head holding a weight plate.'),
('Plate Hollow Hold',2,'Pick your upper back and your legs off the ground. Your body should be in a banana shape.'),
('Plate Internally Rotated Rear Delt Fly',1,'With plates in either hand, bend your knees with your feet slightly bowed out. Hinge forward with a flat back.'),
('Plate Internally Rotated Rear Delt Fly',2,'Maintain an overhand grip and internally rotated shoulders.'),
('Plate Internally Rotated Rear Delt Fly',3,'Raise your arms backward toward the ceiling while maintaining a light band in your elbows.'),
('Plate Lateral Lunge',1,'Stand with feet hip-width apart and the plate held in front of the torso.'),
('Plate Lateral Lunge',2,'Take a step to the side with one foot, bending the knee and lowering the hips into a lunge.'),
('Plate Lateral Lunge',3,'Push through the front foot to return to the starting position.'),
('Plate Lateral Lunge',4,'Repeat on the other side by stepping to the other side with the other foot.'),
('Plate Lateral Raise',1,'Stand with feet shoulder-width apart and grip two plates in each hand at your sides.'),
('Plate Lateral Raise',2,'Keeping your arms straight, raise the plates out to your sides until they are in line with your shoulders.'),
('Plate Lateral Raise',3,'Lower the plates back to your sides with control. Repeat for desired number of reps.'),
('Plate Overhead Carry',1,'Start by standing upright with your feet shoulder-width apart. Hold a single weight plate overhead with both hands, keeping your arms extended straight above your head.'),
('Plate Overhead Carry',2,'Begin walking forward, taking slow and steady steps while maintaining a straight line. Your focus should be on maintaining balance and control of the weight plate overhead.'),
('Plate Overhead Carry',3,'As you walk, continue to keep your arms extended and the weight plate overhead. Try to maintain good posture and avoid leaning forward or backward, as this could result in losing control of the weight plate.'),
('Plate Overhead Carry',4,'Continue walking for a set distance or for a certain amount of time, keeping your focus on proper form and technique. When finished, return to the starting position and repeat as desired.'),
('Plate Overhead Press To Tricep Extension',1,'Brace your core and press the weight plate overhead until your arms are fully extended. Keep your shoulders down and back.'),
('Plate Overhead Press To Tricep Extension',2,'While your arms are fully extended, lower the weight behind your head to perform the extension'),
('Plate Overhead Press To Tricep Extension',3,'After completing the extension, lower the weight to your chest, and perform the overhead press. Repeat'),
('Plate Overhead Shrug',1,'Stand tall with a weight plate overhead.'),
('Plate Overhead Shrug',2,'Elevated and depress your scapula.'),
('Plate Overhead Shrug',3,'Avoid leaning forward or backwards to keep pressure off of your lumbar spine.'),
('Plate Overhead Squat',1,'Hold a weight plate at arm\'s length overhead, with your arms fully extended. The plate should be directly above your head and your elbows should be locked.'),
('Plate Overhead Squat',2,'Begin to bend your knees, lowering your body as far as you can while keeping the weight plate overhead. Make sure to keep your back straight and your chest lifted.'),
('Plate Overhead Squat',3,'Once your thighs are parallel to the ground or as low as you can go, pause for a moment.'),
('Plate Overhead Squat',4,'Push through your heels to return to a standing position, keeping the weight plate overhead the entire time.'),
('Plate Overhead Tricep Extension',1,'Stand or sit with a weight plate in your hands, arms extended straight above your head'),
('Plate Overhead Tricep Extension',2,'Lower the weight plate behind your head by bending at the elbows.'),
('Plate Overhead Tricep Extension',3,'Keep your elbows close to your head and shoulders relaxed.'),
('Plate Overhead Tricep Extension',4,'Push the weight plate back up to starting position, extending your arms fully.'),
('Plate Overhead Walking Lunge',1,'Stand tall with a plate overhead.'),
('Plate Overhead Walking Lunge',2,'Step with one foot forward bringing your back knee to the floor. Gently tap your knee then drive through your front leg.'),
('Plate Overhead Walking Lunge',3,'Go back to a standing position and then step forward with the opposing legs.'),
('Plate Pinch Grip Deadlift',1,'Stand facing the plate with your feet shoulder-width apart and the plate positioned between your feet.'),
('Plate Pinch Grip Deadlift',2,'Bend down and grasp the plate from the top edges with both hands, making sure your thumbs and fingers are evenly spaced.'),
('Plate Pinch Grip Deadlift',3,'Keep your back straight, chest up and core engaged, and stand up with the plate, keeping it close to your body.'),
('Plate Pinch Grip Deadlift',4,'Lower the plate back down to the ground, keeping control and maintaining good posture.'),
('Plate Pinch Grip Farmer\'s Carry',1,'Stand tall holding two plates in each hand with a pinch grip.'),
('Plate Pinch Grip Farmer\'s Carry',2,'Walk for the desired distance or time.'),
('Plate Pinch Grip Row',1,'Make sure to keep your elbow close to your body and your core engaged throughout the movement.'),
('Plate Pinch Grip Row',2,'Bend forward at your hips while maintaining a flat back.'),
('Plate Pinch Grip Row',3,'Pull the plate toward your upper abdomen.'),
('Plate Pinch Grip Row',4,'Lower the weight in a controlled manner and repeat.'),
('Plate Pinch Grip Side Bend',1,'Stand straight with the plate held at your side'),
('Plate Pinch Grip Side Bend',2,'Keep your hips and shoulders facing forward, bend to one side slowly'),
('Plate Pinch Grip Side Bend',3,'Return to the upright position.'),
('Plate Pinch Grip Side Bend',4,'Switch hands and repeat'),
('Plate Reach',1,'Start in a standing position with a plate against your chest.'),
('Plate Reach',2,'Press the plate away from your body until your elbows are extended.'),
('Plate Rear Delt Fly',1,'Keep your back straight and bend forward slightly at the waist.'),
('Plate Rear Delt Fly',2,'With arms extended, raise the weights out to your sides until they are in line with your shoulders.'),
('Plate Rear Delt Fly',3,'Pause briefly and then lower the weights back to the starting position.'),
('Plate Reverse Lunge',1,'Hold the plate at chest height close to your body'),
('Plate Reverse Lunge',2,'Take a big step backwards with your left leg, lowering your body until your left thigh is parallel to the ground and your right knee is bent at a 90-degree angle.'),
('Plate Reverse Lunge',3,'Push through your right heel to return to standing, bringing your left leg back to starting position.'),
('Plate Reverse Lunge',4,'Repeat the movement on the other side, stepping backwards with your right leg and lowering your body until your right thigh is parallel to the ground and your left knee is bent at a 90-degree angle.'),
('Plate Reverse Lunge Twist',1,'Step back with your right foot into a lunge position, both knees bent at 90 degrees.'),
('Plate Reverse Lunge Twist',2,'Twist your torso to the right, keeping the plate close to your chest.'),
('Plate Reverse Lunge Twist',3,'Push through your front foot to return to the starting position and repeat on the other side.'),
('Plate Russian Twist',1,'Start by sitting on the floor with your knees bent and feet flat on the ground'),
('Plate Russian Twist',2,'Engage your core muscles by pulling your belly button toward your spine.'),
('Plate Russian Twist',3,'Slowly twist your upper body to the right, keeping your feet flat on the ground and your back straight.'),
('Plate Russian Twist',4,'Hold for a second and then twist to the left, holding for another second.'),
('Plate Single Leg Deadlift',1,'Engage your core and straighten your legs to lift the plate off the ground.'),
('Plate Single Leg Deadlift',2,'Stand on one leg, keeping the other leg off the ground, while holding the plate in front of your body.'),
('Plate Single Leg Deadlift',3,'Keep your back straight and maintain a neutral head position while looking straight ahead.'),
('Plate Single Leg Deadlift',4,'Lower the plate back down to the ground while keeping your balance on one leg.'),
('Plate Single Leg Pinch Grip Deadlift',1,'Stand with your feet shoulder-width apart and facing forwards. Grip the sides of a weight plate with your palms facing down.'),
('Plate Single Leg Pinch Grip Deadlift',2,'Balance on one foot, as you raise the weight keep your arms and back straight, while you bring your other foot back towards the ground'),
('Plate Single Leg Pinch Grip Deadlift',3,'Keep four raised leg straight and in alignment with your back as you lower the plate back down to the starting position.'),
('Plate Situp',1,'Start by lying on your back on a mat with your legs bent and feet flat on the ground.'),
('Plate Situp',2,'Hold a weight plate over your head with both hands, making sure to keep your arms straight.'),
('Plate Situp',3,'Engage your core and use your abdominal muscles to sit up, keeping the weight plate towards the ceiling.'),
('Plate Squat',1,'Stand with feet shoulder-width apart and hold a weight plate in front of your chest with both hands.'),
('Plate Squat',2,'Keep your back straight, lower your body as if you were sitting back into a chair.'),
('Plate Squat',3,'Go as low as you can while keeping your heels flat on the ground, then push through your heels to return to the starting position.'),
('Plate Squat Hold',1,'Start by standing with your feet shoulder-width apart, with a weight plate held in both hands at chest height.'),
('Plate Squat Hold',2,'Lower your body by bending your knees and hips, keeping your back straight and your weight in your heels.'),
('Plate Squat Hold',3,'Go down until your thighs are parallel to the floor, then pause for a moment.'),
('Plate Squat Hold',4,'Hold the squat position for the desired amount of time, keeping the weight plate steady and your core engaged.'),
('Plate Squat Hold Curl',1,'Lower into a squat position, keeping the plate at chest height.'),
('Plate Squat Hold Curl',2,'Slowly curl the plate towards your shoulders, keeping your elbows close to your body.'),
('Plate Squat Hold Curl',3,'Hold for a moment at the top of the curl before lowering the plate back to chest height.'),
('Plate Squat Hold Curl',4,'Repeat the curls as you hold the squat position.'),
('Plate Squat Hold Reach',1,'Hold the plate with both hands at chest height.'),
('Plate Squat Hold Reach',2,'Keeping your core tight and your chest up, squat down as low as you can go while keeping your feet flat on the ground.'),
('Plate Squat Hold Reach',3,'Hold the squat position and reach the plate forward, keeping your arms straight and your back straight.'),
('Plate Squat Hold Reach',4,'Return the plate to your chest while you hold the squat position and repeat reaching the plate in front of you'),
('Plate Squat Reach',1,'Stand holding a weight plate at chest height with both hands.'),
('Plate Squat Reach',2,'Lower into a squat, extending the plate in front of you at chest height'),
('Plate Squat Reach',3,'As you stand back up, pull the plate back into your chest.'),
('Plate Staggered Deadlift',1,'Start by standing with your feet shoulder-width apart and holding a weight plate.'),
('Plate Staggered Deadlift',2,'Place one foot slightly behind the other, with the heel of your back foot elevated.'),
('Plate Staggered Deadlift',3,'From this starting position, bend at the hips and knees to lower the plate towards the ground, keeping your back straight and your core engaged.'),
('Plate Staggered Deadlift',4,'Once the plate is below your knees, drive through your heels to stand back up to the starting position.'),
('Plate Staggered Pinch Grip Deadlift',1,'Start by standing with your feet shoulder-width apart and holding two plates with a pinch grip.'),
('Plate Staggered Pinch Grip Deadlift',2,'Place one foot slightly behind the other, with the heel of your back foot elevated.'),
('Plate Staggered Pinch Grip Deadlift',3,'From this starting position, bend at the hips and knees to lower the plates towards the ground, keeping your back straight and your core engaged.'),
('Plate Staggered Waiters Bow',1,'Set up a bar at mid way up your quad. Place the working leg against the bar.'),
('Plate Staggered Waiters Bow',2,'Place one foot behind. You should only be on your toes on that back foot. Your front foot should be planted flat the entire time.'),
('Plate Staggered Waiters Bow',3,'Bend your back knee and push your hips back. Look for a stretch in your front hamstring.'),
('Plate Staggered Waiters Bow',4,'When you feel the stretch, push your hips forward again until you\'re back in a standing position.'),
('Plate Standing Twist',1,'Stand with a plate extended away from your body. Elbows mostly extended.'),
('Plate Standing Twist',2,'Rotate at the upper spine while keeping your lumbar spine in a neutral position.'),
('Plate Standing Twist',3,'Do not let the plate go behind your body.'),
('Plate Superman',1,'Lay flat on the ground on your stomach with your arms extended overhead. Hold a plate with a neutral grip.'),
('Plate Superman',2,'Lift your legs and chest off the ground simultaneously and hold for a 1 count at the top.'),
('Plate Superman',3,'Relax your lower back and lower your legs and chest back to the floor.'),
('Plate Superman Hold',1,'Hold a plate in both hands.'),
('Plate Superman Hold',2,'Pull your arms and legs off the ground while and hold that position.'),
('Plate Thruster',1,'Start with the plate at chest height. Begin a squat.'),
('Plate Thruster',2,'Make sure to hit parallel depth. On your way back up, use the momentum you generate with your legs to help push the plate into an overhead position.'),
('Plate Thruster',3,'Let the plate return to chest height before initiating the next squat.'),
('Plate Waiters Bow',1,'Place a barbell at about midway up your thigh. Press your quads into the barbell. Hold a plate up to your chest.'),
('Plate Waiters Bow',2,'Push your hips back while leaving your knees mostly extended. Look for a stretch in your hamstrings.'),
('Plate Waiters Bow',3,'When you feel the stretch, push your hips forward until you\'re back in a standing position.'),
('Plate Weighted Dead Hang',1,'Attach weight to yourself using a dip belt. Grip a pull-up bar with palms facing forward.'),
('Plate Weighted Dead Hang',2,'Hang with arms fully extended.'),
('Plate Weighted Dead Hang',3,'Hold for recommended amount of time, keeping your core engaged.'),
('Plate Weighted Dip',1,'Use a dip belt to attach a plate to yourself. Grip bars with arms straight, shoulders above hands. Keep legs straight or bent.'),
('Plate Weighted Dip',2,'Lower slowly until elbows are at 90 degrees.'),
('Plate Weighted Dip',3,'Push back up to start position, extending arms fully.'),
('Plate Weighted Inverted Row',1,'Lay underneath a fixed horizontal bar and grab the bar with a wide overhand grip. Place a plate on your chest.'),
('Plate Weighted Inverted Row',2,'Pull your body straight up to the bar.'),
('Plate Weighted Inverted Row',3,'Return to the starting position, your arms fully extended. Repeat.'),
('Plate Wood Chopper',1,'Stand with a shoulder width stance. Begin with the plate near one of your quads.'),
('Plate Wood Chopper',2,'Rotate at your upper spine to engage the obliques.'),
('Plate Wood Chopper',3,'You can pivot your back foot to keep from generating too much torque at the knee.'),
('Plow Back Rowing Preps',1,'Sit tall with legs extended, arms holding straps forward.'),
('Plow Back Rowing Preps',2,'Begin with arms long, shoulders relaxed and chest open.'),
('Plow Back Rowing Preps',3,'Pull arms down and back in a plow motion, engaging lats.'),
('Plow Back Rowing Preps',4,'Return to start with control, maintaining upright posture and tension.'),
('Pole Overhead Squat',1,'Stand with your feet slightly wider than shoulder-width apart and hold a pole overhead, using an overhand grip.'),
('Pole Overhead Squat',2,'Begin the squat by bending at the hips and knees, keeping your core tight and the dumbbells balanced overhead.'),
('Pole Overhead Squat',3,'Lower your body as far as you can while keeping the dumbbells overhead, then push back up to the starting position.'),
('Pole Overhead Squat',4,'Repeat for the desired number of repetitions, making sure to keep your back straight, chest lifted, and the dumbbells stable overhead throughout the entire movement.'),
('Pole Rotation',1,'Start with the pole in front of you with an overhand wider than shoulder width grip.'),
('Pole Rotation',2,'Rotate both arms overhead and behind you while leaving your elbows mostly extended.'),
('Pull Ups',1,'Grasp the bar with an overhand grip, arms and shoulders fully extended.'),
('Pull Ups',2,'Pull your body up until your chin is above the bar.'),
('Pull Ups',3,'Lower your body back to starting position.'),
('Puppy Pose',1,'Begin in a tabletop position with your hands and knees on the ground.'),
('Puppy Pose',2,'Walk your hands forward as you lower your chest towards the ground.'),
('Puppy Pose',3,'Keep your hips over your knees and extend your arms out in front of you.'),
('Puppy Pose',4,'Hold for a few breaths and then release.'),
('Push Up',1,'Place your hands firmly on the ground, directly under shoulders.'),
('Push Up',2,'Flatten your back so your entire body is straight and slowly lower your body'),
('Push Up',3,'Draw shoulder blades back and down, keeping elbows tucked close to your body'),
('Push Up',4,'Exhale as you push back to the starting position.'),
('Pushup Position Shoulder Clock',1,'Wrap a loop band around your wrists and get yourself in a pushup position.'),
('Pushup Position Shoulder Clock',2,'Support your body on one arm, while the other moves out taping the hour positions of the clock.'),
('Pushup Position Shoulder Clock',3,'If you\'re moving your right arm it should be taping 12, 1, ..., 6.'),
('Pushup Position Shoulder Clock',4,'If you\'re moving your left arm it should be taping 12, 11, ..., 6.'),
('Pushup to Renegade Row',1,'Start in a high plank position with a pair of dumbbells positioned under your shoulders. Your hands should grip the dumbbells, palms facing each other.'),
('Pushup to Renegade Row',2,'Keep your core engaged and your back straight as you row one dumbbell up towards your hip, keeping your elbow close to your body.'),
('Pushup to Renegade Row',3,'Lower the dumbbell back down to the starting position and repeat on the other side.'),
('Pyramid Pose',1,'Begin in Tadasana (Mountain Pose).'),
('Pyramid Pose',2,'Step your left foot back about 3-4 feet and place your heel down, keeping your toes pointing forward.'),
('Pyramid Pose',3,'Inhale and lengthen your spine, then exhale and fold forward from your hips, bringing your hands to the floor on either side of your right foot.'),
('Pyramid Pose',4,'Hold for several breaths, then switch sides and repeat.'),
('Pyramid Pose Blocks',1,'Begin in Tadasana (Mountain Pose) with two blocks at the top of your mat.'),
('Pyramid Pose Blocks',2,'Step your left foot back about 3-4 feet and place your heel down, keeping your toes pointing forward.'),
('Pyramid Pose Blocks',3,'Place the blocks on either side of your right foot at a height that allows you to comfortably place your hands on them.'),
('Pyramid Pose Blocks',4,'Inhale and lengthen your spine, then exhale and fold forward from your hips, bringing your hands to the blocks. Hold for several breaths, then switch sides and repeat.'),
('Pyramid Pose Calf Blocks',1,'Start standing with a flat and vertical block on the matt'),
('Pyramid Pose Calf Blocks',2,'Bend forward, placing hand on vertical block, and front of foot on the flat block.'),
('Pyramid Pose Calf Blocks',3,'Press the bottom of your foot towards the ground, and repeat on each side.'),
('Pyramid Prayer',1,'Stand with your feet hip-width apart and place your hands on a table, chair, or any elevated surface in front of you.'),
('Pyramid Prayer',2,'Walk your feet back until your torso is parallel to the ground, and your elbows are resting on the surface.'),
('Pyramid Prayer',3,'Relax your head and neck, and breathe deeply.'),
('Pyramid Prayer',4,'Hold for a few breaths, then release.'),
('Quads Stretch Variation Four',1,'Lay flat on your belly. Extend one arm out in front of you, placing your palm on the floor. With your other arm, grab the top of your foot.'),
('Quads Stretch Variation Four',2,'Keeping your upper leg flat on the floor, pull your foot towards your buttocks to engage the stretch.'),
('Quads Stretch Variation Four',3,'Pause for a few seconds, and then repeat the stretch with your other leg.'),
('Quads Stretch Variation One',1,'Stand perpendicular to a wall, using one arm against the wall for balance. With your other arm, grab the top of your foot.'),
('Quads Stretch Variation One',2,'Pull your leg upwards and back to engage your quads, pausing at the apex of the stretch for a few seconds.'),
('Quads Stretch Variation One',3,'Return to starting position and repeat with your other leg.'),
('Quads Stretch Variation Three',1,'Lay flat on your belly, with both hands reach back and grab the tops of your feet.'),
('Quads Stretch Variation Three',2,'Keeping your upper legs flat on the ground, pull both of your feet towards your buttocks.'),
('Quads Stretch Variation Three',3,'Pause at the apex of the stretch, then return to starting position.'),
('Quads Stretch Variation Two',1,'Place one foot flat on the ground in front of you at a 90 degree angle. With your other leg, balance upon your knee, placing the tip of your foot against the wall behind you for balance.'),
('Quads Stretch Variation Two',2,'Place your hands on your knee in front of you, and lean forward so that your knee extends over your foot.'),
('Quads Stretch Variation Two',3,'Pause at the apex of the stretch, and slowly return to starting position. Repeat with your other leg.'),
('Reach And Catch',1,'Lay flat on your back with both hands over one leg.'),
('Reach And Catch',2,'Reach toward your knee flexing your abs and obliques.'),
('Reach And Catch',3,'Do the prescribed amount of reps, then switch sides.'),
('Reclining Pigeon Pose',1,'Lie down on your back with your knees bent and your feet on the ground.'),
('Reclining Pigeon Pose',2,'Cross your right ankle over your left knee, creating a figure four shape.'),
('Reclining Pigeon Pose',3,'Use your hands to gently pull your left knee towards your chest, feeling a stretch in your right hip.'),
('Reclining Pigeon Pose',4,'Hold the pose for a few breaths, then switch sides and repeat.'),
('Resisted Radial Deviation',1,'Stand up straight with your arms by your side and a light dumbbell or lever in your hand.'),
('Resisted Radial Deviation',2,'Point the dumbbell/lever to the ground before lifting it towards the ceiling.'),
('Resisted Radial Deviation',3,'Only move the wrist.'),
('Restful Cow Face Pose Legs',1,'Start in a seated position with your legs extended in front of you.'),
('Restful Cow Face Pose Legs',2,'Cross your right leg over your left leg, placing your right foot on the floor beside your left hip.'),
('Restful Cow Face Pose Legs',3,'Cross your left leg over your right leg, placing your left foot on the floor beside your right hip.'),
('Restful Cow Face Pose Legs',4,'Relax your arms by your sides or place them on your abdomen and take deep breaths.'),
('Reverse Crunch Kick Up',1,'Perform a reverse crunch and then kick your legs up toward the ceiling.'),
('Reverse Crunch Kick Up',2,'Flex at the hips and knees until your hips land back on the bench, then kick your legs back out to the starting position.'),
('Reverse Expansion Bicep Curls Kneeling',1,'Kneel tall, arms long, palms forward.'),
('Reverse Expansion Bicep Curls Kneeling',2,'Set shoulders down, engage core and glutes.'),
('Reverse Expansion Bicep Curls Kneeling',3,'Bend elbows, curling hands toward shoulders without leaning back.'),
('Reverse Expansion Bicep Curls Kneeling',4,'Extend arms slowly, maintaining upright posture and strap tension.'),
('Reverse Expansion Salute Kneeling',1,'Kneel tall facing straps, elbows bent, palms facing forward.'),
('Reverse Expansion Salute Kneeling',2,'Keep elbows lifted and shoulders relaxed.'),
('Reverse Expansion Salute Kneeling',3,'Press arms upward on a diagonal, extending elbows fully.'),
('Reverse Expansion Salute Kneeling',4,'Bend elbows to return with control, maintaining vertical torso.'),
('Reverse Expansion Teardrops Inward Kneeling',1,'Kneel tall facing straps, arms slightly forward and elevated.'),
('Reverse Expansion Teardrops Inward Kneeling',2,'Initiate movement from shoulder blades, drawing arms inward and down.'),
('Reverse Expansion Teardrops Inward Kneeling',3,'Create small teardrop shape, keeping neck relaxed.'),
('Reverse Expansion Teardrops Inward Kneeling',4,'Return to start smoothly, maintaining continuous tension.'),
('Reverse Expansion Teardrops Outward Kneeling',1,'Kneel tall facing straps, arms forward and slightly elevated.'),
('Reverse Expansion Teardrops Outward Kneeling',2,'Pull arms outward and down in a controlled teardrop pattern.'),
('Reverse Expansion Teardrops Outward Kneeling',3,'Emphasize upper-back engagement, ribs stacked over pelvis.'),
('Reverse Expansion Teardrops Outward Kneeling',4,'Return with control, maintaining steady breathing.'),
('Reverse Prayer',1,'Start seated or standing with your arms at your sides.'),
('Reverse Prayer',2,'Bring your hands behind your back and interlace your fingers with your palms facing up.'),
('Reverse Prayer',3,'Inhale and draw your shoulder blades together, lifting your chest.'),
('Reverse Prayer',4,'Exhale and gently press your hands down towards the floor as you continue to lift your chest.'),
('Revolved Head To Knee',1,'Sit on the floor with your legs extended in front of you.'),
('Revolved Head To Knee',2,'Bend your right knee and bring your heel towards your perineum.'),
('Revolved Head To Knee',3,'Place your left hand on the outside of your right knee and twist your body to the right.'),
('Revolved Head To Knee',4,'Reach your right hand towards your left foot and look up towards the ceiling. Hold the pose for a few breaths before switching sides.'),
('Revolved Side Angle Pose With Prayer Hands',1,'Begin in Warrior II pose, with your right foot forward and your left foot back.'),
('Revolved Side Angle Pose With Prayer Hands',2,'Bring your hands together in a prayer position at your heart.'),
('Revolved Side Angle Pose With Prayer Hands',3,'Exhale and twist your torso to the right, placing your left elbow on the outside of your right knee.'),
('Revolved Side Angle Pose With Prayer Hands',4,'Hold for several breaths and then repeat on the other side.'),
('Revolved Side Angle Pose With Prayer Hands Beginner',1,'Begin in a low lunge position with your right foot forward and your left knee on the ground.'),
('Revolved Side Angle Pose With Prayer Hands Beginner',2,'Bring your hands together in a prayer position at your heart.'),
('Revolved Side Angle Pose With Prayer Hands Beginner',3,'Exhale and twist your torso to the right, placing your left elbow on the outside of your right knee.'),
('Revolved Side Angle Pose With Prayer Hands Beginner',4,'Hold for several breaths and then repeat on the other side.'),
('Ring Chin Up',1,'Grab the rings shoulder width apart with a supinated grip (palms facing you)'),
('Ring Chin Up',2,'With your body hanging and arms fully extended, pull yourself up until your chin is past the rings.'),
('Ring Chin Up',3,'Slowly return to starting position. Repeat.'),
('Ring Curl',1,'Stand holding gymnastic rings with your arms extended in front of you, palms facing up.'),
('Ring Curl',2,'Curl rings towards shoulders, squeezing biceps.'),
('Ring Curl',3,'Slowly lower rings back to starting position, keeping control. Repeat.'),
('Ring Pull Up',1,'Grasp the rings with an overhand grip, arms and shoulders fully extended.'),
('Ring Pull Up',2,'Pull your body up until your chin is above the rings.'),
('Ring Pull Up',3,'Lower your body back to starting position.'),
('Ring Rear Delt Fly',1,'Stand facing rings and grab the handles.'),
('Ring Rear Delt Fly',2,'Step forward so that your body is in a plank position, with your arms straight and your body in a straight line from your head to your heels.'),
('Ring Rear Delt Fly',3,'Keeping your arms straight, slowly lift your arms out to the side, keeping them at the same height as your shoulders. Your body should form a \"T\" shape.'),
('Ring Row',1,'Set up rings at a high point.'),
('Ring Row',2,'Grip rings and lean back, arms extended.'),
('Ring Row',3,'Pull chest to rings, keeping body straight.'),
('Ring Skullcrusher',1,'Attach the ring straps to a high point. Stand on your tip toes.'),
('Ring Skullcrusher',2,'Your arms should be extended in front of you.'),
('Ring Skullcrusher',3,'Break at the elbows until your forearms touch your biceps. Then extend your elbows back to the start.'),
('Ring Standing Archer Pushup',1,'Position rings shoulder-width apart, grasp handles, extend legs behind.'),
('Ring Standing Archer Pushup',2,'Lower chest to rings, bend one elbow, while extending your other arm out to the side. Push yourself back to the start.'),
('Ring Standing Archer Pushup',3,'Then switch arms and repeat.'),
('Ring Standing Chest Fly',1,'Start by adjusting the rings straps to chest height. Stand facing the rings with your feet shoulder-width apart.'),
('Ring Standing Chest Fly',2,'Grasp the rings\' handles with both hands, keeping your arms extended and your shoulders away from your ears.'),
('Ring Standing Chest Fly',3,'Lean forward, keeping your arms extended and your core engaged. Your body should form a slight diagonal line from your ankles to your head.'),
('Ring Standing Chest Fly',4,'Slowly bring your arms towards each other, in front of your chest, while keeping your core engaged and your body in a stable position.'),
('Ring Standing Pushup',1,'Start by setting up the rings to a secure anchor point and adjust the straps so that they hang about waist height when you stand under them.'),
('Ring Standing Pushup',2,'Stand facing the rings grab the handles with both hands, and step forward so that your body is in a plank position with your hands directly beneath your shoulders.'),
('Ring Standing Pushup',3,'Lower your body down by bending your elbows until your chest nearly touches the handles. Keep your core tight and your body in a straight line.'),
('Ring Standing Pushup',4,'Push your body back up to the starting position, straightening your arms as you do so. Make sure to engage your chest, triceps, and core throughout the movement.'),
('Ring Standing Roll Out',1,'Grasp the rings, keeping your arms extended and your shoulders away from your ears.'),
('Ring Standing Roll Out',2,'Keep your abs engaged, roll forward onto your toes, and extend your arms in front of you.'),
('Ring Standing Roll Out',3,'Slowly lower your body down toward the ground, keeping your arms straight and your abs engaged.'),
('Ring Standing Roll Out',4,'When your head gets between your arms, pause for a moment and then use your abs to pull your body back up to the starting position.'),
('Ring Twisting Chin Up',1,'Grab the rings shoulder width apart with a pronated grip (palms facing away).'),
('Ring Twisting Chin Up',2,'With your body hanging and arms fully extended, pull yourself up and rotate your fists until your chin is past the rings.'),
('Ring Twisting Chin Up',3,'Slowly return to starting position. Repeat.'),
('Rotator Cuff External Rotations 1',1,'Stand side ways to a pulley (you can also attach a theraband to a fixed point instead).'),
('Rotator Cuff External Rotations 1',2,'Hold the grip (or band) with the arm away from the pulley. Bring that arm by your side and bend it at 90°'),
('Rotator Cuff External Rotations 1',3,'Externally rotate the palm against the resistance. Your elbow should remain by your ribs throughout the movement'),
('Rotator Cuff External Rotations 2',1,'Stand on one end of a theraband with one foot and hold the loose end with your opposite hand.'),
('Rotator Cuff External Rotations 2',2,'Bring your elbow forward by 45° (at shouder) but maintain a 90° angle at elbow'),
('Rotator Cuff External Rotations 2',3,'Externally rotate against the resistance.'),
('Rotator Cuff External Rotations 3',1,'Abduct your arm at 90° (raise your arm to the side).'),
('Rotator Cuff External Rotations 3',2,'Keep a 90° angle at elbow, forearm parallel to the ground.'),
('Rotator Cuff External Rotations 3',3,'Externally rotate against resistance.'),
('Rotator Cuff Mobilisation Lacrosse Ball',1,'Lie on the floor and place a massage ball under your rotator cuff.'),
('Rotator Cuff Mobilisation Lacrosse Ball',2,'Support your elbow with your opposite arm.'),
('Rotator Cuff Mobilisation Lacrosse Ball',3,'Roll into the ball to increase pressure and away from it to reduce.'),
('Rower Pike',1,'Place your feet on the rower seat and get in to a plank position.'),
('Rower Pike',2,'Pull your hips straight up toward the ceiling.'),
('Rower Pike',3,'Lower your hips until you\'re back in a plank position.'),
('Runners Lunge',1,'Begin in Downward Facing Dog pose (Adho Mukha Svanasana).'),
('Runners Lunge',2,'Step your right foot forward between your hands.'),
('Runners Lunge',3,'Place your left knee on the ground behind you and slide it back until you feel a stretch in your left hip flexor.'),
('Runners Lunge',4,'Keep your hands on the ground or lift them to the sky and hold for a few breaths before repeating on the other side.'),
('Running Lying On The Back',1,'Lie supine with feet on bar, legs fully extended.'),
('Running Lying On The Back',2,'Alternate lowering one heel while the other stays lifted.'),
('Running Lying On The Back',3,'Switch rhythmically, maintaining stable pelvis and quiet upper body.'),
('Running Lying On The Back',4,'Continue alternating, emphasizing ankle mobility and control.'),
('Scapular Depression',1,'From the standing or seated position straighten your back.'),
('Scapular Depression',2,'Pull the shoulders back but keep them relaxed.'),
('Scapular Depression',3,'Move shoulders away from your ears and return to the starting, relaxed position.'),
('Scapular Protraction',1,'From the standing or seated position straighten your back.'),
('Scapular Protraction',2,'Pull the shoulders back but keep them relaxed.'),
('Scapular Protraction',3,'Move shoulders forward and return to the starting, relaxed position.'),
('Scapular Retraction',1,'From the standing or seated position straighten your back.'),
('Scapular Retraction',2,'Pull the shoulders back but keep them relaxed.'),
('Scapular Retraction',3,'Move shoulders backwards and return to the starting, relaxed position.'),
('Scissor Kick',1,'Lie on your back, hands under your buttocks or on the ground for support.'),
('Scissor Kick',2,'Lift legs off the ground, alternate crossing them in a scissor motion.'),
('Scorpion Twist Pose',1,'Begin in a downward-facing dog pose.'),
('Scorpion Twist Pose',2,'Slowly lift one leg up towards the ceiling, keeping your hips level and your toes pointed.'),
('Scorpion Twist Pose',3,'Bend your lifted leg and try to touch your toes to the back of your head.'),
('Scorpion Twist Pose',4,'Once you have a firm grip with your toes, slowly begin to twist your torso towards the lifted leg.'),
('Scorpion Twist Pose',5,'Keep your hands and feet firmly planted on the ground as you hold the pose for a few breaths. Release the pose and repeat on the other side.'),
('Seated Arm Stretch',1,'Sit cross-legged on the floor.'),
('Seated Arm Stretch',2,'Extend your arms straight out in front of you, palms facing forward.'),
('Seated Arm Stretch',3,'Cross your right arm over your left arm and interlace your fingers.'),
('Seated Arm Stretch',4,'Pull your hands away from your body and hold for a few breaths, then release and repeat with the opposite arm on top.'),
('Seated Box Jump',1,'Setup two boxes. One to jump on and one to sit.'),
('Seated Box Jump',2,'Go from a seated position and pop your hips forward forcefully.'),
('Seated Box Jump',3,'Jump and land on the box softly.'),
('Seated Cervical Flexion Isometric',1,'Sit on a bench maintaining an upright posture. Place the heel of one palm on your forehead.'),
('Seated Cervical Flexion Isometric',2,'Press the palm into the forehead while your front neck muscles are resisting the pressure.'),
('Seated Cervical Flexion Isometric',3,'Apply steady pressure. Do not allow movement in the neck.'),
('Seated Cervical Rotation Hold',1,'Sit on a bench maintaining an upright posture.'),
('Seated Cervical Rotation Hold',2,'Place the heel of one palm on the side front of your forehead, and the other on the side back of your head.'),
('Seated Cervical Rotation Hold',3,'Try rotating your head towards the side of the palm that is to the side front of the head.'),
('Seated Cervical Rotation Hold',4,'Apply steady pressure, while both palms resist the rotation.'),
('Seated Cervical Side Flexion Hold',1,'Sit on a bench maintaining an upright posture.'),
('Seated Cervical Side Flexion Hold',2,'Place the heel of one palm on the side of your head.'),
('Seated Cervical Side Flexion Hold',3,'Apply pressure into the side of the head while your neck muscles resist the pressure.'),
('Seated Forward Bend',1,'Sit on the floor with your legs extended in front of you.'),
('Seated Forward Bend',2,'Inhale and lengthen your spine, then exhale and fold forward from your hips, keeping your spine long.'),
('Seated Forward Bend',3,'Reach for your feet or ankles, keeping your elbows straight.'),
('Seated Forward Bend',4,'Hold for several breaths, then release.'),
('Seated Lateral Raise',1,'Sit upright on bench or box.'),
('Seated Lateral Raise',2,'Hold dumbbells at sides'),
('Seated Lateral Raise',3,'Lift arms to shoulder height.'),
('Seated Manual Cervical Extensor Mobilisation',1,'Sit on a bench, keeping a upright posture'),
('Seated Manual Cervical Extensor Mobilisation',2,'Place your index and middle finger right under the base of your skull and slightly to the side'),
('Seated Manual Cervical Extensor Mobilisation',3,'Find the tender spot and gently work on it with your fingertips'),
('Seated Median Nerve Slider',1,'Abduct your arm at 90°, elbow straight and palm facing up.'),
('Seated Median Nerve Slider',2,'Bend your elbow and wrist, bringing the fist close to the shoulder, while leaning the head to the opposite side.'),
('Seated Median Nerve Slider',3,'Alternate between these positions to mobilise the median nerve.'),
('Seated Median Nerve Tensioner',1,'Abduct your arm at 90°, elbow straight and palm facing up.'),
('Seated Median Nerve Tensioner',2,'Extend your wrist (point the fingers downwards).'),
('Seated Median Nerve Tensioner',3,'Tilt the head to the opposite side making sure you do not bend the elbow.'),
('Seated Median Nerve Tensioner',4,'Find the position of maximum tension (without pain) and hold.'),
('Seated Radial Nerve Slider',1,'From the seated position bring your arm out to the side with the palm facing back.'),
('Seated Radial Nerve Slider',2,'Flex your wrist at the same time you are leaning your head towards your outstretched arm.'),
('Seated Radial Nerve Slider',3,'Bend your head away from the the outstretched arm while simultaneously extending the wrist.'),
('Seated Radial Nerve Tensioner',1,'Bend your elbow bringing your thumb to the centre of your chest.'),
('Seated Radial Nerve Tensioner',2,'Extend your elbow to the side with the palm facing back, and wrist flexed'),
('Seated Radial Nerve Tensioner',3,'As your extending the arm, lean your head towards the opposite shoulder'),
('Seated Radial Nerve Tensioner',4,'Once you reach maximum tension (without pain) hold the position'),
('Seated Shoulder Abduction',1,'Stand or sit with your arm by your side, palm facing forward.'),
('Seated Shoulder Abduction',2,'Reach your hand out to the side and over your head without bending the elbow'),
('Seated Shoulder Abduction',3,'The thumb leads the movement.'),
('Seated Side Bend Pose',1,'Sit comfortably on the floor with your legs crossed.'),
('Seated Side Bend Pose',2,'Inhale and raise your right arm above your head.'),
('Seated Side Bend Pose',3,'As you exhale, bend your body to the left side and rest your left hand on the ground.'),
('Seated Side Bend Pose',4,'Look up towards the ceiling and hold the pose for a few breaths. Then switch sides and repeat the pose on the other side.'),
('Seated Twist',1,'Begin seated with your legs extended in front of you.'),
('Seated Twist',2,'Bend your right knee and place your foot on the floor next to your left thigh.'),
('Seated Twist',3,'Inhale and reach your left arm up towards the ceiling.'),
('Seated Twist',4,'Exhale and twist to the right, placing your left elbow on the outside of your right knee. Hold for a few breaths and then repeat on the other side.'),
('Seated Ulnar Nerve Slider',1,'Abduct your arm at 90° palm facing down.'),
('Seated Ulnar Nerve Slider',2,'Bend your elbow and wrist bringing your front of your fingertips to your temple while leaning the head towards the the arm.'),
('Seated Ulnar Nerve Slider',3,'Lean the head away from the arm as you extend the elbow and flex the wrist.'),
('Seated Ulnar Nerve Slider',4,'Alternate between positions to mobilise the ulnar nerve.'),
('Seated Ulnar Nerve Tensioner',1,'Abduct your arm at 90° palm facing down.'),
('Seated Ulnar Nerve Tensioner',2,'Bend your elbow and wrist to bring the palm to face the ceiling while leaning the head towards the opposite shoulder.'),
('Seated Ulnar Nerve Tensioner',3,'Find the position of maximum tension (without pain) and hold.'),
('Seated Ulnar Nerve Tensioner',4,'To increase the stretch, press the palm against the face and try to point the elbow up.'),
('Serratus Activation Cross Punch',1,'Lie on your back with your knees bent and the feet flat on the floor.'),
('Serratus Activation Cross Punch',2,'Hold a dumbbell over your shoulder with a straight arm.'),
('Serratus Activation Cross Punch',3,'Form the sign of the cross adding a protraction (punch) on every end of the cross, including the middle position.'),
('Serratus Activation Plank',1,'Support your weight on your forearms and toes (plank).'),
('Serratus Activation Plank',2,'Allow your upper back to sink in between the shoulder blades.'),
('Serratus Activation Plank',3,'Push your elbows into the ground and slightly forward, and move the shoulder blades away from the spine.'),
('Shoulder Abduction Stretch',1,'Stand sideways to a wall.'),
('Shoulder Abduction Stretch',2,'Raise the arm that is on the side of the wall and place the blade of the palm against the wall.'),
('Shoulder Abduction Stretch',3,'Slide your arm up over your head and step in towards the wall to increase the stretch.'),
('Shoulder External Internal Rotation',1,'Externally and internally rotate the shoulder to mobilise the joint on the specific movement.'),
('Shoulder External Rotation Deceleration',1,'Lie on a bench facing down.'),
('Shoulder External Rotation Deceleration',2,'Bring your arm parallel to the ground and bent at the elbow, while holding a weighted ball.'),
('Shoulder External Rotation Deceleration',3,'Externally rotate your shoulder letting go of the ball.'),
('Shoulder External Rotation Deceleration',4,'Grab the ball before it falls to the ground.'),
('Shoulder Flexion Thoracic Extensions',1,'Place a tube roller or half tube on the ground parallel to your body.'),
('Shoulder Flexion Thoracic Extensions',2,'Lie on the tube making sure your whole back and neck are supported.'),
('Shoulder Flexion Thoracic Extensions',3,'Knees bent and on the ground, lower back flat on the tube and chin tucked in.'),
('Shoulder Flexion Thoracic Extensions',4,'Bring your arms by you hips and pull shoulders back.'),
('Shoulder Flexion Thoracic Extensions',5,'This is your starting position. Raise arms and drop them back towards the ground over your head'),
('Shoulder Flexion Wall Stretch',1,'Stand facing a wall.'),
('Shoulder Flexion Wall Stretch',2,'Raise your arm above the head and place it on the wall, thumb facing back.'),
('Shoulder Flexion Wall Stretch',3,'Slide the arm up and lean into the wall to increase the stretch.'),
('Shoulder Girdle Stability Circles',1,'Stand facing a wall. Pin a gym ball between your palm and the wall (elbow straight).'),
('Shoulder Girdle Stability Circles',2,'Push your arm into the ball without leaning into it.'),
('Shoulder Girdle Stability Circles',3,'While applying pressure, form the sign of the cross (up/down/left/right) and circles.'),
('Shoulders Stretch Variation Four',1,'Stand with you feet shoulder width apart. Place one arm across the front of your chest at shoulder height, press the forearm of your other arm above the elbow, hooking the stretching arm with your hand.'),
('Shoulders Stretch Variation Four',2,'Press the arm until it is straight and rotate your upper torso to engage the stretch even deeper.'),
('Shoulders Stretch Variation Four',3,'Repeat with your other arm.'),
('Shoulders Stretch Variation One',1,'Reach one arm behind your body, with your elbow pointing upward behind your head.'),
('Shoulders Stretch Variation One',2,'Assist the stretch with your other hand on your elbow to engage your shoulder.'),
('Shoulders Stretch Variation One',3,'Pause for a few seconds, then repeat the stretch with your other arm.'),
('Shoulders Stretch Variation Three',1,'Place the top of your hand into the small of your back, your arm at a 90 degree angle.'),
('Shoulders Stretch Variation Three',2,'Hold your elbow with the other arm, and slowly pull the arm forward until you feel your shoulder engaged in the stretch. Pause at the apex of the stretch and return to the starting position.'),
('Shoulders Stretch Variation Three',3,'Return to starting position, and repeat with your other arm.'),
('Shoulders Stretch Variation Two',1,'Start with your arms at either side. Begin by pushing your shoulders forward and in towards your chest.'),
('Shoulders Stretch Variation Two',2,'Continue the circular motion with your shoulders, pinching up towards your ears, and then extending your chest outwards while you finish the motion.'),
('Shoulders Stretch Variation Two',3,'Repeat as necessary.'),
('Side Lunges',1,'Take a slow, lateral step to the right.'),
('Side Lunges',2,'Extend the left knee, and drive your weight into your right side.'),
('Side Lunges',3,'Flex your knee and lower your body.'),
('Side Lunges',4,'Push back to the starting position.'),
('Side Lying External Rotator Cuff Stretch',1,'Lie on your side with the under arm outstretched in front of you.'),
('Side Lying External Rotator Cuff Stretch',2,'Pull your shoulder back to stabilise the scapula.'),
('Side Lying External Rotator Cuff Stretch',3,'Bend your elbow at 90° or more.'),
('Side Lying External Rotator Cuff Stretch',4,'Use your top arm to press the palm of the under arm out.'),
('Side Plank Reach Through',1,'Begin in an elbow side plank position.'),
('Side Plank Reach Through',2,'Reach for the ceiling with your off hand.'),
('Side Plank Reach Through',3,'Rotate at the mid and upper spine and reach through the open space between the floor and your torso.'),
('Side Plank Reach Through',4,'Reach backwards, and then rotate back into the starting position.'),
('Side Plank Up Down',1,'Start with your elbow and hip on the ground. Either neutral fist or flat hand on the ground.'),
('Side Plank Up Down',2,'Begin in a side plank position, and then drop your hips to the floor.'),
('Side Plank Up Down',3,'Pull your hips back to the ceiling to finish the rep.'),
('Side Shoulder Girdle Stability Circles',1,'Stand sideways to a wall. Pin a gym ball between your palm and the wall (elbow straight).'),
('Side Shoulder Girdle Stability Circles',2,'Push your arm into the ball without leaning into it.'),
('Side Shoulder Girdle Stability Circles',3,'While applying pressure, form the sign of the cross (up/down/left/right) and circles.'),
('Side Splits Skating',1,'Stand on reformer, feet on platforms, hinged forward, spine neutral.'),
('Side Splits Skating',2,'Push carriage out.'),
('Side Splits Skating',3,'Return to center with control, maintaining upright posture.'),
('Side Twist Kneeling',1,'Kneel tall sideways, hands holding straps, arms extended forward.'),
('Side Twist Kneeling',2,'Engage core, rotate torso away from anchor.'),
('Side Twist Kneeling',3,'Keep hips square and shoulders stacked.'),
('Sideways Scissor Kick',1,'Lift both legs off the ground.'),
('Sideways Scissor Kick',2,'Bring both legs outward, then cross both legs over one another.'),
('Sideways Scissor Kick',3,'Alternating which leg goes on top.'),
('Single Arm Overhead Squat',1,'Stand with your feet shoulder-width apart and a dumbbell in your right hand, extending it overhead.'),
('Single Arm Overhead Squat',2,'Inhale and begin to squat down, keeping the dumbbell overhead and your back straight.'),
('Single Arm Overhead Squat',3,'Go down as far as you can while still maintaining control, then exhale and return to standing position, keeping the dumbbell overhead. Repeat for desired reps and then switch to the other arm.'),
('Single Arm Rapunzel Pushdown',1,'Stand with a band anchored to a high point. Face away from the band. Hold the loop in one hand.'),
('Single Arm Rapunzel Pushdown',2,'Keep your elbow tucked in to your side. Extend your elbow. When you extend, don\'t let your upper arm raise. The band should land over your shoulder.'),
('Single Leg Balance 2',1,'Stand upright with a braced core.'),
('Single Leg Balance 2',2,'Choose the supporting leg and shift your weight on that, while lifting the other slightly off the ground.'),
('Single Leg Balance 2',3,'Try to maintain your balance while bouncing a tennis ball off the wall or ground.'),
('Single Leg Bicycle',1,'Lie supine, one knee bent, opposite leg extended.'),
('Single Leg Bicycle',2,'Press through one leg. Simultaneously pull the raised leg up to a table top position.'),
('Single Leg Bicycle',3,'As you lower, bring your non-working leg back into extension.'),
('Single Leg Bosu Ball Balance 2',1,'Place the supporting leg on the middle of a bosu ball.'),
('Single Leg Bosu Ball Balance 2',2,'Keep the knee of the suspended leg slightly bent.'),
('Single Leg Bosu Ball Balance 2',3,'Try to maintain your balance on the bosu ball while bouncing a tennis ball off the wall.'),
('Single Leg Box Jump',1,'Stand with a shoulder width stance.'),
('Single Leg Box Jump',2,'Jump onto your box and land with one foot.'),
('Single Leg Box Jump',3,'Try to land in the middle of the box and land as softly as possible.'),
('Single Leg Glute Bridge',1,'Tense your glutes and raise your hips towards the ceiling.'),
('Single Leg Glute Bridge',2,'Once you are at the highest point you can manage, hold the position for a few seconds, and then slowly return to the starting position.'),
('Single Leg Glute Bridge',3,'Push your hips up, so that your butt is elevated and your back straight.'),
('Single Leg Glute Bridge',4,'Lie down with one knee bent and and one with a slight bend.'),
('Single Leg One Leg Bent',1,'Lie supine, one foot planted, opposite leg in a tabletop position.'),
('Single Leg One Leg Bent',2,'Engage core, maintain neutral pelvis.'),
('Single Leg Slider Hamstring Curl 2',1,'Lie on your back with bent knees and heels on a slider.'),
('Single Leg Slider Hamstring Curl 2',2,'Perform a posterior pelvic tilt (flatten your lower back on the ground).'),
('Single Leg Slider Hamstring Curl 2',3,'Press the heels into the ground to raise your hips off it.'),
('Single Leg Slider Hamstring Curl 2',4,'Extend and bend the working leg.'),
('Single Legged Romanian Deadlifts',1,'Stand with your feet shoulder-width apart and knees slightly bent and raise one leg.'),
('Single Legged Romanian Deadlifts',2,'Without changing the bend in your knee, bend at your hips, and lower your torso until it\'s almost parallel to the floor.'),
('Single Legged Romanian Deadlifts',3,'Tense your glutes and then bring yourself back to the starting position.'),
('Slalom Mountain Climber',1,'Start in a plank position with hands directly under shoulders.'),
('Slalom Mountain Climber',2,'Drive knees toward left elbow.'),
('Slalom Mountain Climber',3,'Go back to starting position, then drive knees to right elbow, mimicking a zigzag slalom motion.'),
('Slider Hamstring Curl',1,'Lie on your back with slightly bent knees and heels on sliders.'),
('Slider Hamstring Curl',2,'Pull your heels towards your glutes to lift your hips off the ground.'),
('Slider Hamstring Curl',3,'Extend knees to starting position, but do not rest hips on ground.'),
('Slider Hamstring Curl Eccentric',1,'Bend your knees so your feet are flat on the floor with heels under knees and toes raised.'),
('Slider Hamstring Curl Eccentric',2,'Place sliders under your heels. Perform a posterior pelvic tilt (flatten your lower back against the ground).'),
('Slider Hamstring Curl Eccentric',3,'Push through your heels into the ground, lifting your hips up to the point where there is a straight line from your chest to your knees.'),
('Slider Hamstring Curl Eccentric',4,'Extend your legs in a slow, controlled manner, to lower your bum to the ground.'),
('Slider Hamstring Curl Eccentric',5,'Casually bend knees before repeating.'),
('Slider Hamstring Curl Single Leg',1,'Lie on your back keeping both knees bent.'),
('Slider Hamstring Curl Single Leg',2,'Have a slider under the heel of the working leg.'),
('Slider Hamstring Curl Single Leg',3,'Extend and bend the working lag applying gentle downwards pressure.'),
('Slow Tempo Mountain Climber',1,'To perform a bodyweight mountain climber, start in a plank position with your hands placed directly under your shoulders.'),
('Slow Tempo Mountain Climber',2,'Bring your right knee towards your chest, keeping your foot close to your hand. Quickly switch legs, bringing your left knee towards your chest.'),
('Slow Tempo Mountain Climber',3,'Continue this movement, alternating legs, at a slow pace for a set amount of time or repetitions.'),
('Smith Machine Assisted Pullup',1,'Grasp the bar with an overhand grip, arms and shoulders fully extended. Leave your feet on the floor.'),
('Smith Machine Assisted Pullup',2,'Pull your body up until your chin is above the bar. Use your legs top assist you up.'),
('Smith Machine Assisted Pullup',3,'Lower your body back to starting position.'),
('Smith Machine Bench Press',1,'Lay flat on the bench with your feet on the ground. With straight arms unrack the bar.'),
('Smith Machine Bench Press',2,'Lower the bar to your mid chest'),
('Smith Machine Bench Press',3,'Raise the bar until you\'ve locked your elbows.'),
('Smith Machine Bodyweight Skullcrusher',1,'Hold the smith bar and lean forward.'),
('Smith Machine Bodyweight Skullcrusher',2,'Keep your elbows tucked in and then flex and extend at the elbows.'),
('Smith Machine Calf Raise',1,'Place the bar on your back'),
('Smith Machine Calf Raise',2,'Start with feet flat on the ground'),
('Smith Machine Calf Raise',3,'Extend your heels upwards while keeping your knees stationary, and pause at the contracted position.'),
('Smith Machine Calf Raise',4,'Slowly return to the starting position. Repeat.'),
('Smith Machine Close Grip Bench Press',1,'Lay flat on the bench with your feet on the ground. With a narrow grip on the bar, straighten your arms'),
('Smith Machine Close Grip Bench Press',2,'Lower the bar to your lower-mid chest'),
('Smith Machine Close Grip Bench Press',3,'Slowly raise the bar until you\'ve locked your elbows.'),
('Smith Machine Drag Curl',1,'Grab the bar with an underhand grip.'),
('Smith Machine Drag Curl',2,'Pull your elbows straight back and let the bar drag against your upper body (or very close to it).'),
('Smith Machine Glute Kickback',1,'Start on your hands and knees with one foot placed on the bottom of the bar.'),
('Smith Machine Glute Kickback',2,'Keeping your core braced, your back flat, and your moving leg bent at a 90 degree angle, drive the heel of your working leg up the ceiling while squeezing your glute.'),
('Smith Machine Glute Kickback',3,'Follow the movement path as you bring your knee back down to the ground beneath your hip, keeping your knee bent to maintain control of the bar.'),
('Smith Machine Glute Kickback',4,'Repeat for the desired number of reps before switching sides.'),
('Smith Machine Guillotine Bench Press',1,'Lie on the flat bench, grasp the bar at shoulder level with your palms facing forward.'),
('Smith Machine Guillotine Bench Press',2,'Slowly lower the bar to your chest, keeping your elbows flared out.'),
('Smith Machine Guillotine Bench Press',3,'Once you feel a stretch in your chest press the weight back up.'),
('Smith Machine Hanging Knee Tuck',1,'Put a hip thrust pad on the smith machine bar at neck height. Put both arms over the bar and pull your feet off the ground.'),
('Smith Machine Hanging Knee Tuck',2,'Pull your knees to your chest and flex your abs.'),
('Smith Machine Hip Thrust',1,'Sit on the ground with a bench behind you. Have the bar over your legs just above your hips.'),
('Smith Machine Hip Thrust',2,'Lean back against the bench so that your shoulders are resting upon it, stretch your arms out to either side using the bench as support.'),
('Smith Machine Hip Thrust',3,'Raise the weight by driving through your feet and extending your hips upwards. Support the weight with your shoulders and feet.'),
('Smith Machine Hip Thrust',4,'Slowly extend as far as you can, and then slowly return to the starting position.'),
('Smith Machine Incline Bench Press',1,'Position the bench between 30 and 45 degrees.'),
('Smith Machine Incline Bench Press',2,'Lay flat on the bench with your feet on the ground. With straight arms unrack the bar.'),
('Smith Machine Incline Bench Press',3,'Lower the bar to your mid chest'),
('Smith Machine Incline Bench Press',4,'Raise the bar (slowly and controlled) until you\'ve locked your elbows.'),
('Smith Machine Inverted Row',1,'Lay underneath a fixed horizontal bar and grab the bar with a wide overhand grip.'),
('Smith Machine Inverted Row',2,'Pull your body straight up to the bar.'),
('Smith Machine Inverted Row',3,'Return to the starting position, your arms fully extended. Repeat.'),
('Smith Machine Leg Press',1,'Place your legs on the bar with your feet at shoulder width.'),
('Smith Machine Leg Press',2,'Release the weight and extend your legs fully, without locking your knees.'),
('Smith Machine Leg Press',3,'Lower the weight until your legs are at a 90° angle (but DO NOT allow your butt and lower back to rise off of the floor. This will put your lower back in a rounded position, which is very dangerous.)'),
('Smith Machine Leg Press',4,'Raise the weight back to starting position.'),
('Smith Machine Narrow Stance Squat',1,'Place the bar on top of your traps. Take a narrow stance.'),
('Smith Machine Narrow Stance Squat',2,'Push your hips back and break at the knees. Push your elbows forward to keep yourself from getting pitched too far forward.'),
('Smith Machine Narrow Stance Squat',3,'Aim to get your hamstrings to parallel with the floor.'),
('Smith Machine Narrow Stance Squat',4,'Push your heels into the floor and squat back to a standing position.'),
('Smith Machine Oblique Crunch',1,'Lay on your side with your knees bent.'),
('Smith Machine Oblique Crunch',2,'Hold the bar extended over you.'),
('Smith Machine Oblique Crunch',3,'Lift yourself up by flexing your obliques.'),
('Smith Machine Overhand Row',1,'Start hinged forward with a flat back. Make sure your elbows are fully extended.'),
('Smith Machine Overhand Row',2,'Pull the bar to your sternum.'),
('Smith Machine Pushup',1,'Place hands on the bar, in push-up position.'),
('Smith Machine Pushup',2,'Lower yourself to the bar, maintaining proper form.'),
('Smith Machine Reverse Crunch Hip Raise',1,'Lay flat on the ground. With your feet on the bar.'),
('Smith Machine Reverse Crunch Hip Raise',2,'Lift your hips off the ground.'),
('Smith Machine Reverse Lunge',1,'Start by standing with your feet about hip-width apart, with the bar on your shoulders. Your feet should be slightly pointed outward, and your shoulders should be down and relaxed.'),
('Smith Machine Reverse Lunge',2,'Step backward with one foot, lowering your body until your front thigh is parallel to the ground and your back knee is hovering just above the ground.'),
('Smith Machine Reverse Lunge',3,'Push off your back foot, returning to the starting position.'),
('Smith Machine Romanian Deadlift',1,'Take a shoulder width, double overhand or mixed grip.'),
('Smith Machine Romanian Deadlift',2,'Push your hips back while leaving your knees mostly extended. Look for a stretch in your hamstrings.'),
('Smith Machine Romanian Deadlift',3,'When you feel the stretch, push your hips forward until you\'re back in a standing position.'),
('Smith Machine Seated Calf Raise',1,'Start by sitting on a bench or box with the bar resting on your knees. Your feet should be flat on the ground, about hip-width apart.'),
('Smith Machine Seated Calf Raise',2,'Place your hands on the barbell for support, and lift your heels off the ground.'),
('Smith Machine Seated Calf Raise',3,'Hold this position for a moment, then slowly lower your heels back to the ground.'),
('Smith Machine Seated Overhead Press',1,'Sit on a bench with back support. Raise the bar to shoulder height with your palms forward.'),
('Smith Machine Seated Overhead Press',2,'Raise the bar upwards and pause at the contracted position.'),
('Smith Machine Seated Overhead Press',3,'Lower the weight back to starting position.'),
('Smith Machine Side Bend',1,'Stand beside the bar.'),
('Smith Machine Side Bend',2,'Keep your hips and shoulders facing forward, bend to one side slowly'),
('Smith Machine Side Bend',3,'Return to the upright position.'),
('Smith Machine Side Bend',4,'Switch hands and repeat.'),
('Smith Machine Side Plank Up Down',1,'Start by lying on your side with your feet stacked on top of each other and the bar on your hip.'),
('Smith Machine Side Plank Up Down',2,'Place your bottom elbow on the ground beneath your shoulder and engage your core to raise your hips off the ground.'),
('Smith Machine Side Plank Up Down',3,'Your hips will do all the moving. Think, \"hips up, hips down.\"'),
('Smith Machine Single Leg Hip Thrust',1,'Start by lying on a bench with your foot on the ground and a barbell on your hips.'),
('Smith Machine Single Leg Hip Thrust',2,'Lift one leg off the ground and engage your glutes to raise your hips up towards the ceiling.'),
('Smith Machine Single Leg Hip Thrust',3,'From this starting position, slowly lower your hips back down to the starting position.'),
('Smith Machine Sissy Squat',1,'Stand facing away from the machine, positioning your feet slightly wider than shoulder-width apart to provide a stable base, and then reach behind you to firmly grip the bar with both hands, maintaining an overhand grip.'),
('Smith Machine Sissy Squat',2,'Initiate the movement by leaning backward, allowing your upper body to incline while simultaneously bending your knees. As you descend, maintain control'),
('Smith Machine Sissy Squat',3,'drive through your quadriceps while pushing your hips forward, gradually straightening your knees. Maintain a slow, controlled pace'),
('Smith Machine Situp',1,'Set up the Smith machine bar at an appropriate height.'),
('Smith Machine Situp',2,'Lie on your back beneath the bar, gripping it with your hands.'),
('Smith Machine Situp',3,'Engage your core, lift your upper body toward the bar, and exhale.'),
('Smith Machine Situp',4,'Lower your upper body back down in a controlled manner, inhaling.'),
('Smith Machine Skullcrusher',1,'Take a shoulder width grip. Break at the elbows. Try to keep your elbows tucked in. Don\'t let them flare out.'),
('Smith Machine Skullcrusher',2,'Stop the bar a few inches from your forehead and extend your elbows back up.'),
('Smith Machine Split Squat',1,'Take a large step forward with one leg until your shoulders are under the smith machine'),
('Smith Machine Split Squat',2,'lower your body until your back knee nearly touches the ground. Your front knee should be bent at a 90-degree angle, and your back leg should be straight.'),
('Smith Machine Split Squat',3,'Push through the heel of your front foot to raise your body back to the starting position.'),
('Smith Machine Squat',1,'Stand with your feet shoulder-width apart. Maintain the natural arch in your back and put the bar on your back. Squeezing your shoulder blades and raise your chest.'),
('Smith Machine Squat',2,'Grip the bar across your shoulders and support it on your upper back. Unwrack the smith machine by straightening your legs.'),
('Smith Machine Squat',3,'Bend your knees as you lower the weight without altering the form of your back until your hips are below your knees.'),
('Smith Machine Squat',4,'Raise the bar back to starting position, lift with your legs and exhale at the top.'),
('Smith Machine Staggered Deadlift',1,'Place one foot behind. You should only be on your toes on that back foot. Your front foot should be planted flat the entire time.'),
('Smith Machine Staggered Deadlift',2,'Bend your back knee and push your hips back. Look for a stretch in your front hamstring.'),
('Smith Machine Staggered Deadlift',3,'When you feel the stretch, push your hips forward again until you\'re back in a standing position.'),
('Smith Machine Sumo Romanian Deadlift',1,'Stance width can vary with a sumo DL. Some prefer toes near the plates. Others prefer a more narrow stance to get more drive off the floor.'),
('Smith Machine Sumo Romanian Deadlift',2,'Make sure your arms are inside your legs. The bar should be just over your mid-foot. Flatten your back and unrack the bar'),
('Smith Machine Sumo Romanian Deadlift',3,'Leave your knees mostly extended and flex and extend your hips.'),
('Smith Machine Underhand Row',1,'Begin by standing in front of a bar with your feet about hip-width apart.'),
('Smith Machine Underhand Row',2,'Bend at the hips and knees to grab the bar with a supinated (underhand) grip, positioning the bar about an inch away from your shins.'),
('Smith Machine Underhand Row',3,'Keeping your back straight and your core engaged, use your back muscles to lift the bar straight up towards your chest.'),
('Smith Machine Underhand Row',4,'As the bar reaches your chest, pause briefly, and then lower the bar back to the starting position.'),
('Smith Machine Upright Row',1,'Take a double overhand roughly shoulder width grip.'),
('Smith Machine Upright Row',2,'Pull your elbows straight up the ceiling. Aim to get the bar to chin level or slightly higher.'),
('Smith Machine Upright Row',3,'lower the bar and repeat.'),
('Sphinx Pose',1,'Start by lying down on your stomach on a yoga mat or a comfortable surface.'),
('Sphinx Pose',2,'Place your elbows underneath your shoulders, keeping your forearms parallel to each other.'),
('Sphinx Pose',3,'Press your palms and forearms firmly into the ground to lift your chest up, while keeping your hips and legs relaxed.'),
('Sphinx Pose',4,'Make sure your shoulders are relaxed and away from your ears. Gently roll your shoulder blades down and back to open up your chest.'),
('Sphinx Pose',5,'Lengthen your spine by lifting the crown of your head towards the ceiling, while keeping your chin tucked in slightly.'),
('Stability Ball Atomic Push Up',1,'Place feet on a stability ball, hands on the floor in a push-up position.'),
('Stability Ball Atomic Push Up',2,'Lower your chest toward the floor, then push up while tucking knees toward your chest.'),
('Stability Ball Atomic Push Up',3,'Extend legs back to starting position, maintaining control and stability throughout the movement.'),
('Stability Ball Glute Bridge',1,'Start by lying flat on your back with your feet resting on top of a ball.'),
('Stability Ball Glute Bridge',2,'Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the bar.'),
('Stability Ball Glute Bridge',3,'Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.'),
('Stability Ball Goblet Wall Squat',1,'Place a stability ball against a wall at about hip height.'),
('Stability Ball Goblet Wall Squat',2,'Hold a dumbbell in a goblet position.'),
('Stability Ball Goblet Wall Squat',3,'Break at the hips and knees until you hit parallel or just below, then squat back up.'),
('Stability Ball Hamstring Curl',1,'Lie on your back, heels on a stability ball, arms flat, and core engaged.'),
('Stability Ball Hamstring Curl',2,'Lift hips, curl the ball toward you using your hamstrings, keeping control and balance.'),
('Stability Ball Hamstring Curl',3,'Extend legs back to start while keeping hips lifted, then repeat for desired reps.'),
('Stability Ball Hip Thrust',1,'Sit on the floor, place upper back on a stability ball, feet flat, knees bent.'),
('Stability Ball Hip Thrust',2,'Drive hips upward by squeezing glutes, forming a straight line from shoulders to knees.'),
('Stability Ball Hip Thrust',3,'Lower hips slowly without touching the floor, maintaining core engagement, then repeat.'),
('Stability Ball Knee Tuck',1,'Start in a plank position with your feet on a stability ball and hands on the floor.'),
('Stability Ball Knee Tuck',2,'Engage your core and tuck your knees toward your chest, rolling the ball forward carefully.'),
('Stability Ball Knee Tuck',3,'Extend your legs back to the starting position, maintaining balance and control throughout the movement.'),
('Stability Ball Pike',1,'Place your feet on the ball and get in to a plank position.'),
('Stability Ball Pike',2,'Pull your hips straight up toward the ceiling.'),
('Stability Ball Pike',3,'Lower your hips until you\'re back in a plank position.'),
('Stability Ball Push Up',1,'Place your hands firmly on the ground, directly under shoulders. Place your feet on the stability ball.'),
('Stability Ball Push Up',2,'Flatten your back so your entire body is straight and slowly lower your body'),
('Stability Ball Push Up',3,'Draw shoulder blades back and down, keeping elbows tucked close to your body'),
('Stability Ball Push Up',4,'Exhale as you push back to the starting position.'),
('Stability Ball Reverse Hyperextension',1,'Lie face down on a stability ball, hands on the floor, legs extended straight.'),
('Stability Ball Reverse Hyperextension',2,'Engage glutes and lower back, raising legs until aligned with your torso.'),
('Stability Ball Reverse Hyperextension',3,'Slowly lower legs back down without touching the ground, maintaining core engagement. Repeat.'),
('Stability Ball Side Crunch',1,'Lie sideways on a stability ball, feet anchored, hands behind head, core engaged.'),
('Stability Ball Side Crunch',2,'Crunch sideways by contracting obliques, bringing your upper body toward your hip.'),
('Stability Ball Single Leg Hip Thrust',1,'Lie on the ball, one foot on the ground.'),
('Stability Ball Single Leg Hip Thrust',2,'Lift one leg off the ground and engage your glutes to raise your hips up towards the ceiling.'),
('Stability Ball Single Leg Hip Thrust',3,'From this starting position, slowly lower your hips back down to the starting position.'),
('Stability Ball Sissy Squat',1,'Stand with feet hip-width apart, stability ball behind your back against a wall.'),
('Stability Ball Sissy Squat',2,'Lean back onto the ball, bend knees forward, lowering slowly while keeping hips extended.'),
('Stability Ball Sissy Squat',3,'Push through toes, straighten legs, and return to standing while maintaining balance and control.'),
('Stability Ball Stir The Pot',1,'Kneel behind a stability ball, place forearms on top, and engage your core muscles.'),
('Stability Ball Stir The Pot',2,'Lift knees, balance on toes, and slowly move forearms in small controlled circles.'),
('Stability Ball Stir The Pot',3,'Maintain a stable torso, avoid excessive movement, and reverse direction after several rotations.'),
('Stability Ball Straight Leg Glute Bridge',1,'Lie on your back, heels on a stability ball, legs straight, arms by your sides.'),
('Stability Ball Straight Leg Glute Bridge',2,'Press through your heels, lift hips, engage glutes and core, forming a straight line.'),
('Stability Ball Straight Leg Glute Bridge',3,'Slowly lower hips, maintaining control, then repeat for reps.'),
('Stability Ball V Up Pass',1,'Lie on your back, holding a stability ball between your feet, arms extended overhead.'),
('Stability Ball V Up Pass',2,'Engage your core, lift your legs and arms, passing the ball from feet to hands.'),
('Stability Ball V Up Pass',3,'Lower arms and legs back down, then repeat, passing the ball back to feet.'),
('Stability Ball Wall Squat',1,'Stand with feet shoulder-width apart, placing a stability ball between your lower back and wall.'),
('Stability Ball Wall Squat',2,'Slowly squat down by bending knees to 90 degrees, keeping back straight and core engaged.'),
('Stability Ball Wall Squat',3,'Press through heels, straighten legs, and return to standing while maintaining balance and control.'),
('Stability Ball Windshield Wiper',1,'Lie on your back, legs extended, stability ball between your feet, arms out for support.'),
('Stability Ball Windshield Wiper',2,'Engage your core, lift your legs, and rotate them side to side in a controlled motion.'),
('Stability Ball Windshield Wiper',3,'Keep your upper body stable, move slowly, and return to center before switching directions.'),
('Stair Climber',1,'Step onto step, grip handles lightly, maintain tall posture and neutral spine.'),
('Stair Climber',2,'Drive through midfoot, alternate steps smoothly, avoid leaning heavily on handles.'),
('Stair Climber',3,'Set moderate pace, breathe rhythmically, keep knees tracking over toes.'),
('Standing Forward Bend',1,'Stand with your feet hip-width apart.'),
('Standing Forward Bend',2,'Hinge forward at your hips, reaching your hands towards the ground.'),
('Standing Forward Bend',3,'Allow your head to hang heavy and feel a stretch in the back of your legs.'),
('Standing Forward Bend',4,'Hold for a few breaths and then slowly roll up to a standing position.'),
('Standing Forward Bend Blocks',1,'Stand with your feet hip-width apart and place a block on the ground in front of you.'),
('Standing Forward Bend Blocks',2,'Hinge forward at your hips and place your hands on the block.'),
('Standing Forward Bend Blocks',3,'Allow your head to hang heavy and feel a stretch in the back of your legs.'),
('Standing Forward Bend Blocks',4,'Hold for a few breaths and then slowly roll up to a standing position.'),
('Standing Neck Extensions',1,'Pull your shoulders back and away from the ears and straighten the back.'),
('Standing Neck Extensions',2,'Lean your head back trying to keep the front of the neck straight.'),
('Standing Neck Extensions',3,'Point your chin to the ceiling.'),
('Standing Neck Flexions',1,'Pull your shoulders back and away from the ears and straighten the back.'),
('Standing Neck Flexions',2,'Tuck your chin in and drop your head forwards without rounding the back.'),
('Standing Neck Mobility Circumductions',1,'Pull your shoulders back and away from the ears and straighten the back'),
('Standing Neck Mobility Circumductions',2,'Circumduct the head both clockwise and anti-clockwise making sure you are working on the end range throughout the movement.'),
('Standing Neck Rotations',1,'Pull your shoulders back and away from the ears and straighten the back.'),
('Standing Neck Rotations',2,'Rotate your head from side to side without rounding your shoulders.'),
('Standing Neck Side Flexions',1,'Pull your shoulders back and away from the ears and straighten the back.'),
('Standing Neck Side Flexions',2,'Lean your head to the side (bring your ear to your shoulder) without shrugging your shoulder or leaning the spine to the side.'),
('Standing Shoulder Abduction',1,'Stand up straight holding a dowel. The stretching arms palm should face forward'),
('Standing Shoulder Abduction',2,'Push the dowel to the side with the opposite arm.'),
('Standing Shoulder Abduction',3,'This in turn will raise the stretching arm over the head.'),
('Standing Shoulder Flexion Mobility',1,'From the standing position grab the dowel with one arm, thumb on top, in front of the centre of your body.'),
('Standing Shoulder Flexion Mobility',2,'Grab the dowel with your other arm to the side and behind your body.'),
('Standing Shoulder Flexion Mobility',3,'The arm that is back, guides the other in front of you and into the overhead position.'),
('Star Prep',1,'Kneel sideways, one hand on bar, feet staggered.'),
('Star Prep',2,'Push knees outward and raise off hand until at shoulder height.'),
('Stationary Bike',1,'Hold the handles and maintain a neutral spine.'),
('Stationary Bike',2,'Pedal at a moderate pace and try to minimise rocking back and forth.'),
('Stretcher',1,'Place your foot on the leg pad for leverage and grab the attachment.'),
('Stretcher',2,'Start with your arms extended and your head between your arms.'),
('Stretcher',3,'Begin to pull. As you pull, lean backwards until the attachment touches your chest.'),
('Supermans',1,'Lie face down on the floor with your arms fully extended in front of you.'),
('Supermans',2,'Simultaneously raise your arms, legs and chest off of the floor and hold the position.'),
('Supermans',3,'Slowly lower your arms, legs and chest back to the starting position. Repeat.'),
('Supine Twist Lying',1,'Lie down on your back with your arms stretched out to your sides.'),
('Supine Twist Lying',2,'Bend your right knee and bring it towards your chest.'),
('Supine Twist Lying',3,'Slowly twist your body to the left side, bringing your right knee across your body towards the ground on the left side.'),
('Supine Twist Lying',4,'Look towards your right hand and hold the pose for a few breaths before switching sides.'),
('Supported Matsyasana Pose',1,'Sit on the floor with your legs stretched out in front of you.'),
('Supported Matsyasana Pose',2,'Place a yoga block behind you, horizontally, at the base of your spine.'),
('Supported Matsyasana Pose',3,'Slowly recline over the block, supporting yourself with your forearms, until your back is resting on the block.'),
('Supported Matsyasana Pose',4,'Relax your arms at your sides, palms facing up, and breathe deeply.'),
('Swing To Upright Row',1,'Start with a kettlebell between your legs, hinge at hips, swing it upward.'),
('Swing To Upright Row',2,'Lift kettlebell to chest level, elbows high, engaging shoulders.'),
('Swing To Upright Row',3,'Lower kettlebell back down, maintaining control. Repeat for desired reps.'),
('Switch Jump Mountain Climber',1,'Start in a plank position with hands under shoulders.'),
('Switch Jump Mountain Climber',2,'Jump one foot forward, switch legs mid-air.'),
('Switch Jump Mountain Climber',3,'Alternate legs quickly, maintaining a steady plank.'),
('Table Top Pose Variation 1',1,'Start in a tabletop position on your hands and knees with your hands directly under your shoulders and your knees directly under your hips.'),
('Table Top Pose Variation 1',2,'Turn your hands so that your fingers are pointing towards the sides of your mat and the tops of your hands are on the floor.'),
('Table Top Pose Variation 1',3,'Keep your arms straight and your shoulders away from your ears.'),
('Table Top Pose Variation 1',4,'Hold the pose for several breaths or as long as is comfortable.'),
('Table Top Pose Variation 2',1,'Start in a tabletop position on your hands and knees with your hands directly under your shoulders and your knees directly under your hips.'),
('Table Top Pose Variation 2',2,'Turn your hands so that your fingers are pointing towards your knees and the tops of your hands are on the floor.'),
('Table Top Pose Variation 2',3,'Keep your arms straight and your shoulders away from your ears.'),
('Table Top Pose Variation 2',4,'Hold the pose for several breaths or as long as is comfortable.'),
('Table Top Pose Variation 3',1,'Come onto your hands and knees on the mat with your wrists directly under your shoulders and your knees under your hips.'),
('Table Top Pose Variation 3',2,'Turn your palms down and spread your fingers wide, with your fingertips pointing towards your knees.'),
('Table Top Pose Variation 3',3,'Press into your palms and extend your arms fully to lift your shoulders away from your ears.'),
('Table Top Pose Variation 3',4,'Hold the pose for a few breaths, and then release by slowly lowering your hands to the mat and coming back to a neutral tabletop position.'),
('Thoracic Extensions Foam Roller',1,'Place a foam roller on the floor perpendicular to your body.'),
('Thoracic Extensions Foam Roller',2,'Sit and lie back onto it aiming for your mid back to be in contact with the roller.'),
('Thoracic Extensions Foam Roller',3,'Gently tilt your hips backward, squeeze glutes and engage core to protect the lower back.'),
('Thoracic Extensions Foam Roller',4,'Support head on palms, elbows rotated in. Slightly lift hips off the ground.'),
('Thoracic Flexion And Extensions',1,'Bring yourself on all 4\'s. Push the ground away from you, rounding back and shoulders as much as possible.'),
('Thoracic Flexion And Extensions',2,'To enhance the spine flexion suck the belly button in and tuck the tailbone (coccyx) under. Hold this position for a brief moment'),
('Thoracic Flexion And Extensions',3,'Now do the exact opposite, try to bend the spine backwards. Go back and forth on these positions'),
('Thread The Needle Hip Over Knees',1,'Start on your hands and knees in a tabletop position.'),
('Thread The Needle Hip Over Knees',2,'Slide your right knee up between your hands and place your right foot close to your left wrist.'),
('Thread The Needle Hip Over Knees',3,'Take your left leg back and lower it down to the ground, keeping your toes tucked.'),
('Thread The Needle Hip Over Knees',4,'Twist your torso to the right and reach your right arm underneath your left arm, threading the needle. Hold for a few breaths, then switch sides.'),
('Tip Toe Walking',1,'Point your toes into the floor.'),
('Tip Toe Walking',2,'Slowly walk forwards and backward'),
('Tip Toe Walking',3,'Keep your heels in the air as long as possible while walking.'),
('Tip Toe Walking',4,'It may be beneficial to do this last at the end of your workout.'),
('Toe Tap',1,'Stand in front of a low box.'),
('Toe Tap',2,'Bring one foot to the edge of the box and alternate as quickly as possible.'),
('Toe Tap',3,'Only lightly tap your feet to the box.'),
('Trap Bar Deficit Deadlift',1,'Stand on elevated surface inside trap bar, feet hip-width.'),
('Trap Bar Deficit Deadlift',2,'Grip handles, brace core, maintain neutral spine.'),
('Trap Bar Deficit Deadlift',3,'Drive through feet, extend hips and knees to stand.'),
('Trap Bar Deficit Deadlift',4,'Lower under control, maintaining balance on platform.'),
('Trap Bar Pause Deadlift',1,'Set up inside trap bar with strong brace and neutral spine.'),
('Trap Bar Pause Deadlift',2,'Lift bar slightly, pause just below knees.'),
('Trap Bar Pause Deadlift',3,'Hold tension, then continue to full lockout.'),
('Trap Bar Pause Deadlift',4,'Lower bar slowly back to floor.'),
('Trap Bar Reverse Lunge',1,'Stand inside trap bar, grip handles, stand tall.'),
('Trap Bar Reverse Lunge',2,'Step one foot backward into lunge position.'),
('Trap Bar Reverse Lunge',3,'Lower until front thigh is parallel to ground.'),
('Trap Bar Reverse Lunge',4,'Push through front heel to return standing.'),
('Trap Bar Romanian Deadlift',1,'Hold trap bar, stand tall with slight knee bend.'),
('Trap Bar Romanian Deadlift',2,'Hinge hips back, lowering bar along thighs.'),
('Trap Bar Romanian Deadlift',3,'Keep back neutral and tension in hamstrings.'),
('Trap Bar Romanian Deadlift',4,'Drive hips forward to return upright.'),
('Trap Bar Shrug',1,'Stand inside trap bar, arms straight, shoulders relaxed.'),
('Trap Bar Shrug',2,'Elevate shoulders straight upward toward ears.'),
('Trap Bar Shrug',3,'Pause briefly at top, squeezing traps.'),
('Trap Bar Shrug',4,'Lower shoulders slowly to starting position.'),
('Trap Bar Single Leg Deadlift',1,'Stand inside trap bar, lift one foot slightly off ground.'),
('Trap Bar Single Leg Deadlift',2,'Hinge hips back while lowering bar and extending free leg behind.'),
('Trap Bar Single Leg Deadlift',3,'Keep hips square and back neutral throughout movement.'),
('Trap Bar Single Leg Deadlift',4,'Drive through standing foot to return upright.'),
('Trap Bar Split Squat',1,'Take a large step forward with one leg, and lower your body until your back knee nearly touches the ground. Your front knee should be bent at a 90-degree angle, and your back leg should be straight.'),
('Trap Bar Split Squat',2,'Push through the heel of your front foot to raise your body back to the starting position.'),
('Trap Bar Squat',1,'Stand inside trap bar, feet shoulder-width, grip handles.'),
('Trap Bar Squat',2,'Sit hips down and back, keeping chest upright.'),
('Trap Bar Squat',3,'Lower until thighs are at least parallel.'),
('Trap Bar Squat',4,'Push your heels into the floor and squat back to a standing position.'),
('Trap Bar Staggered Romanian Deadlift',1,'Stand inside trap bar. Place one foot behind. You should only be on your toes on that back foot. Your front foot should be planted flat the entire time.'),
('Trap Bar Staggered Romanian Deadlift',2,'Bend your back knee and push your hips back. Look for a stretch in your front hamstring.'),
('Trap Bar Staggered Romanian Deadlift',3,'When you feel the stretch, push your hips forward again until you\'re back in a standing position.'),
('Traps mid back Stretch Variation One',1,'Stand up with your feet shoulder width apart. Place one arm across the front of your chest at shoulder height, press the forearm of your other arm above the elbow, hooking the stretching arm with your hand.'),
('Traps mid back Stretch Variation One',2,'Press the arm until it is straight and rotate your upper torso to engage the stretch even deeper.'),
('Traps mid back Stretch Variation One',3,'Repeat with your other arm.'),
('Traps mid back Stretch Variation Two',1,'Sit on the ground and lay one leg flat and the other over the top.'),
('Traps mid back Stretch Variation Two',2,'Hold your leg with the same side arm and slowly rotate your hips and back.'),
('Traps mid back Stretch Variation Two',3,'Hold at the peak of the stretch, then slowly return to starting position.'),
('Traps mid back Stretch Variation Two',4,'Switch sides and repeat.'),
('Traps Stretch Variation One',1,'Stand upright with your feet shoulder width apart.'),
('Traps Stretch Variation One',2,'Place your left hand on your head and gently pull your head down towards your left shoulder. Then return to centre point.'),
('Traps Stretch Variation One',3,'Repeat, using your right hand pulling towards your right shoulder.'),
('Traps Stretch Variation Three',1,'Stand upright with your feet shoulder width apart.'),
('Traps Stretch Variation Three',2,'Nod your head forward, bringing your chin to your chest.'),
('Traps Stretch Variation Three',3,'You will feel the stretch across your neck.'),
('Traps Stretch Variation Two',1,'Stand upright with your feet shoulder width apart.'),
('Traps Stretch Variation Two',2,'Keeping your chest facing forward, turn your head 90 degrees to the left. Then return to centre point.'),
('Traps Stretch Variation Two',3,'Repeat, turning your head in the other direction.'),
('Treadmill Backwards Walk',1,'Face the opposite direction on the treadmill.'),
('Treadmill Backwards Walk',2,'Hold on to the arms to find your balance.'),
('Treadmill Backwards Walk',3,'Walk backwards pushing your toes through the front of your shoes.'),
('Treadmill Jog',1,'Get the treadmill up to a comfortable speed where you are doing a light jog.'),
('Treadmill Side Shuffle',1,'Face sideways on the treadmill.'),
('Treadmill Side Shuffle',2,'Take a quarter squat position with a wide stance.'),
('Treadmill Side Shuffle',3,'Shuffle sideways for a specified amount of time, then switch sides.'),
('Treadmill Sprint',1,'Get the treadmill up to a speed where you are doing a sprint.'),
('Treadmill Walk',1,'Get the treadmill up to a comfortable speed where you are doing a walk.'),
('Tree Pose',1,'Start in mountain pose, standing with your feet hip-width apart and arms at your sides.'),
('Tree Pose',2,'Shift your weight onto your left foot and bend your right knee, bringing the sole of your right foot to the inside of your left thigh.'),
('Tree Pose',3,'Bring your hands together in front of your heart, or raise them overhead.'),
('Tree Pose',4,'Hold the pose for a few breaths, then release and repeat on the other side.'),
('Triceps Stretch Variation One',1,'Raise your left arm above your head, and bend at the elbow so your hand is resting at the top of your back.'),
('Triceps Stretch Variation One',2,'Use the opposite hand to gently apply pressure to the elbow.'),
('Triceps Stretch Variation One',3,'Hold the stretch for a few seconds then repeat with the other arm.'),
('Triceps Stretch Variation Three',1,'Bend your left arm so your hand is at your shoulder, and hold your elbow with the opposite hand.'),
('Triceps Stretch Variation Three',2,'Gently push on your elbow so it is raised by your head.'),
('Triceps Stretch Variation Three',3,'Hold the stretch for a few seconds then repeat with the other arm.'),
('Triceps Stretch Variation Two',1,'Hold a band so it is in line with your spine. Hold the top with your right hand and the bottom with your left.'),
('Triceps Stretch Variation Two',2,'Keeping the top still, pull down on the band.'),
('Triceps Stretch Variation Two',3,'Hold the stretch for a few seconds then repeat with the other arm.'),
('TRX Ab Rollout',1,'Grasp the TRX handles with both hands, keeping your arms extended and your shoulders away from your ears.'),
('TRX Ab Rollout',2,'Keep your abs engaged, roll forward onto your toes, and extend your arms in front of you.'),
('TRX Ab Rollout',3,'Slowly lower your body down to the ground, keeping your arms straight and your abs engaged.'),
('TRX Ab Rollout',4,'When your head gets between your arms, pause for a moment and then use your abs to pull your body back up to the starting position.'),
('TRX Calf Raise',1,'Hold the TRX straps under your arms and the handles in your armpits.'),
('TRX Calf Raise',2,'Lean forward against the straps.'),
('TRX Calf Raise',3,'Keep your body straight and initiate the calf raise by raising your heels off the ground.'),
('TRX Curl',1,'Hold the TRX straps with an underhand grip and lean back and away from the anchor point.'),
('TRX Curl',2,'Keep your elbows high as you flex your elbows. Pull your fists toward your forehead.'),
('TRX Curtsy Lunge',1,'Stand facing away from the anchor point, holding onto the TRX handles with both hands.'),
('TRX Curtsy Lunge',2,'Step your left foot behind your right, crossing it behind your right leg, and lower yourself into a curtsy lunge.'),
('TRX Curtsy Lunge',3,'Push through your right foot to return to the starting position and repeat the movement with the other leg.'),
('TRX Forearm Plank',1,'Lie face down on the ground and place your forearms on the ground directly under your shoulders.'),
('TRX Forearm Plank',2,'With your feet in the stirrups, kick both feet into the TRX straps and hold the handles above your head.'),
('TRX Forearm Plank',3,'Tighten your abs, glutes, and legs to form a straight line from your head to your feet.'),
('TRX Forearm Side Plank',1,'Lie on your side with your legs straight and your feet resting in the TRX foot cradles.'),
('TRX Forearm Side Plank',2,'Prop yourself up on your forearm and engage your core to maintain a straight line from your head to your feet.'),
('TRX Glute Bridge',1,'Lie on your back with your feet in the foot cradles of the TRX straps, with your knees bent and feet flat on the ground.'),
('TRX Glute Bridge',2,'Place your arms by your sides with your palms facing down.'),
('TRX Glute Bridge',3,'Drive your hips up towards the ceiling, squeezing your glutes and hamstrings at the top of the movement.'),
('TRX Hammer Curl',1,'Grab the TRX straps and lean away from the anchor point.'),
('TRX Hammer Curl',2,'Maintain a neutral grip. Flex your elbows and pull your fists to either sides of your temples.'),
('TRX Hamstring Curl',1,'Start by facing the TRX straps and positioning yourself in a push-up position with your hands on the ground and your feet in the TRX foot cradles.'),
('TRX Hamstring Curl',2,'Keeping your core engaged and body in a straight line, bend your knees and bring your heels towards your glutes.'),
('TRX Hamstring Curl',3,'Pause for a moment at the top of the movement, then slowly lower your legs back to the starting position.'),
('TRX Hand Plank',1,'Start by facing away from the TRX straps and placing your feet in the TRX handles with your palms on the ground.'),
('TRX Hand Plank',2,'Lift your knees off the ground to begin the set.'),
('TRX Hand Plank',3,'Engage your core and maintain this position for the desired amount of time, holding a steady plank.'),
('TRX I Raise',1,'Stand facing the TRX straps and hold onto the handles with an overhand grip, keeping your arms straight and hands slightly wider than shoulder-width apart.'),
('TRX I Raise',2,'Keeping your core engaged, slowly raise your arms forward until they are overhead.'),
('TRX I Raise',3,'Pause for a moment at the top of the movement, then slowly lower your arms back to the starting position.'),
('TRX Jumping Squat',1,'Stand facing the TRX straps and place your feet shoulder-width apart.'),
('TRX Jumping Squat',2,'Begin by lowering into a squat position by bending at the knees and hips, keeping your back straight and chest up.'),
('TRX Jumping Squat',3,'Explosively jump up off the ground, using your arms for momentum if desired.'),
('TRX Jumping Squat',4,'Land softly back in the squat position, making sure to absorb the impact with your legs.'),
('TRX Knee Tuck',1,'Place your feet in the TRX stirrups and get in to a hand plank position.'),
('TRX Knee Tuck',2,'Pull your knees to your chest and flex your abs.'),
('TRX Kneeling Ab Rollout',1,'Begin in a kneeling position with the TRX straps adjusted to mid-calf length.'),
('TRX Kneeling Ab Rollout',2,'Grasp the TRX handles with both hands, keeping your arms extended and your shoulders away from your ears.'),
('TRX Kneeling Ab Rollout',3,'Keep your abs engaged, roll forward onto your toes, and extend your arms in front of you.'),
('TRX Kneeling Ab Rollout',4,'Slowly lower your body down to the ground, keeping your arms straight and your abs engaged.'),
('TRX Lateral Lunge',1,'Grasp the TRX handles with both hands and extend your arms straight in front of you.'),
('TRX Lateral Lunge',2,'Step laterally to one side, keeping your arms extended and your core engaged.'),
('TRX Lateral Lunge',3,'Lower your body into a lunge position, keeping your front knee bent at a 90-degree angle and your back leg straight.'),
('TRX Lateral Lunge',4,'Push off your front foot to return to the starting position, keeping your arms extended and your core engaged.'),
('TRX Mountain Climber',1,'Start in a plank position with the TRX straps adjusted to mid-calf length. Place your feet in the TRX stirrups.'),
('TRX Mountain Climber',2,'Keep your abs engaged, and bring one knee towards your chest while keeping the other leg extended behind you.'),
('TRX Mountain Climber',3,'Switch legs, bringing the opposite knee towards your chest while keeping your abs engaged and your back straight.'),
('TRX Oblique Crunch',1,'Place your feet in the TRX stirrups and get in to a hand plank position.'),
('TRX Oblique Crunch',2,'Pull both knees to your right elbow.'),
('TRX Oblique Crunch',3,'Extend your legs back to the starting position, then pull both knees to the left elbow.'),
('TRX Pec Fly',1,'Start by adjusting the TRX straps to chest height. Stand facing the TRX with your feet shoulder-width apart.'),
('TRX Pec Fly',2,'Grasp the TRX handles with both hands, keeping your arms extended and your shoulders away from your ears.'),
('TRX Pec Fly',3,'Lean forward, keeping your arms extended and your core engaged. Your body should form a slight diagonal line from your ankles to your head.'),
('TRX Pec Fly',4,'Slowly bring your arms towards each other, in front of your chest, while keeping your core engaged and your body in a stable position.'),
('TRX Pike',1,'Place your feet in the stirrups and get in to a plank position.'),
('TRX Pike',2,'Pull your hips straight up toward the ceiling.'),
('TRX Pike',3,'Lower your hips until you\'re back in a plank position.'),
('TRX Pushup',1,'Start by setting up the TRX straps to a secure anchor point and adjust the straps so that they hang about waist height when you stand under them.'),
('TRX Pushup',2,'Stand facing the TRX straps, grab the handles with both hands, and step forward so that your body is in a plank position with your hands directly beneath your shoulders.'),
('TRX Pushup',3,'Lower your body down by bending your elbows until your chest nearly touches the handles. Keep your core tight and your body in a straight line.'),
('TRX Pushup',4,'Push your body back up to the starting position, straightening your arms as you do so. Make sure to engage your chest, triceps, and core throughout the movement.'),
('TRX Rear Delt Fly',1,'Stand facing away from the TRX straps and grab the handles with both hands.'),
('TRX Rear Delt Fly',2,'Step forward so that your body is in a plank position, with your arms straight and your body in a straight line from your head to your heels.'),
('TRX Rear Delt Fly',3,'Keeping your arms straight, slowly lift your arms out to the side, keeping them at the same height as your shoulders. Your body should form a \"T\" shape.'),
('TRX Rear Delt Row',1,'Stand facing away from the TRX straps and grab the handles with both hands.'),
('TRX Rear Delt Row',2,'Step away so your body is leaning away from the anchor point.'),
('TRX Rear Delt Row',3,'Flex your elbows and pull your elbows straight back behind your body.'),
('TRX Rear Delt Row',4,'Make sure to keep your elbows flared outward.'),
('TRX Reverse Curl',1,'Stand facing the TRX straps and grasp the handles with both hands, palms facing away from your body.'),
('TRX Reverse Curl',2,'Walk back until the straps are taut, keeping your arms straight.'),
('TRX Reverse Curl',3,'Slowly curl your hands towards your shoulders, keeping your elbows close to your body.'),
('TRX Reverse Lunge',1,'Hold on to the TRX straps and step away until the strap is taut.'),
('TRX Reverse Lunge',2,'Step backwards with one leg in to a lunge position and gently tap your knee to the floor.'),
('TRX Reverse Lunge',3,'Lunge back to the starting position and repeat with the other leg.'),
('TRX Rotating Row',1,'Grab the TRX straps and lean away from the anchor point until the strap is taut.'),
('TRX Rotating Row',2,'Start with an overhand grip. Pull your elbows back and rotate your grip.'),
('TRX Rotating Row',3,'By the time your elbows reach your side, your palms should be facing upwards.'),
('TRX Single Arm row',1,'Hold the TRX strap with one hand.'),
('TRX Single Arm row',2,'Lean back until the strap is taut. Fully extend your elbow.'),
('TRX Single Arm row',3,'Pull your elbow behind the body. Make sure to avoid twisting. Try to keep your shoulders even.'),
('TRX Skullcrusher',1,'Hold the two TRX straps and lean forward. The straps should be over each shoulder.'),
('TRX Skullcrusher',2,'Keep your elbows tucked in and then flex and extend at the elbows.'),
('TRX Split Squat',1,'Hold the two TRX straps and step away until the straps are taut. Take a split stance.'),
('TRX Split Squat',2,'Bring your back knee to the floor and gently tap the floor.'),
('TRX Split Squat',3,'Use your arms and the TRX to help assist you getting back into the starting position.'),
('TRX Squat',1,'Hold the two TRX straps and lean away from the anchor point.'),
('TRX Squat',2,'Flex at the hips and knees in to a squat position.'),
('TRX Squat',3,'You can use your arms and the straps to assist you back into the starting position.'),
('TRX W Raise',1,'Hold the TRX straps and lean away from the anchor point.'),
('TRX W Raise',2,'Pull your elbows back while externally rotating your shoulder joint. Your arms should make a W shape at the back portion of the exercise.'),
('TRX Y Raise',1,'Hold the TRX straps and lean away from the anchor point until the straps are taut.'),
('TRX Y Raise',2,'Keep both elbows mostly extended and raise both arms out and upwards.'),
('TRX Y Raise',3,'You should make a Y shape with your arms during the back portion of the exercise.'),
('Two Arms Cow Face Pose',1,'Begin in a comfortable seated position on your mat, with your legs crossed and your spine straight.'),
('Two Arms Cow Face Pose',2,'Extend your right arm up toward the ceiling and bend it at the elbow, bringing your right hand behind your head.'),
('Two Arms Cow Face Pose',3,'Reach your left arm behind your back and bend it at the elbow, bringing your left hand up between your shoulder blades.'),
('Two Arms Cow Face Pose',4,'Clasp your hands behind your back, trying to touch your fingertips together. If you can\'t quite reach, you can use a strap or towel to bridge the gap between your hands.'),
('Ulnar Deviations',1,'Stand up straight holding a dowel/lever/weight in one hand.'),
('Ulnar Deviations',2,'Hold the weight so it points behind you and towards the ground.'),
('Ulnar Deviations',3,'Squeeze your grip to raise the weight.'),
('Underhand Pulldown',1,'Use the Straight Bar attachment. Hold with an underhand grip.'),
('Underhand Pulldown',2,'Hold the attachment as you sit on the machine and put your legs under the leg pads.'),
('Underhand Pulldown',3,'Pull the bar to your clavicle, then raise back up until your arm are extended.'),
('Urdhva Dhanurasana Wheel Pose',1,'Lie down on your back with your feet hip-distance apart and your knees bent.'),
('Urdhva Dhanurasana Wheel Pose',2,'Place your hands on the floor beside your head, fingertips pointing towards your shoulders.'),
('Urdhva Dhanurasana Wheel Pose',3,'Push your feet and hands into the floor, lift your hips up and straighten your arms.'),
('Urdhva Dhanurasana Wheel Pose',4,'Lift your chest towards the ceiling and hold the pose for a few breaths before lowering back down.'),
('Vajrasana Variation 1',1,'Begin in a kneeling position with your knees together and your shins and feet on the floor.'),
('Vajrasana Variation 1',2,'Sit back on your heels and place your palms face down on your thighs, with your fingers pointing towards your knees.'),
('Vajrasana Variation 1',3,'Relax your shoulders and take deep breaths.'),
('Vajrasana Variation 1',4,'Hold the pose for several breaths or as long as is comfortable.'),
('Vertical Leg Press',1,'Lay on the pad and place your feet on the foot plate.'),
('Vertical Leg Press',2,'Lift the plate up and disengage the holding hook.'),
('Vertical Leg Press',3,'Lower the weight. Stop before your lower back rounds off the pad.'),
('Vertical Leg Press',4,'Press the weight back to the starting position.'),
('Walk Your Downward Dog',1,'Begin in a downward-facing dog position with your hands shoulder-width apart and your feet hip-width apart.'),
('Walk Your Downward Dog',2,'Walk your feet towards your hands, bending your knees as needed to allow your heels to touch the mat.'),
('Walk Your Downward Dog',3,'Press your palms and fingers into the mat and lift your hips up towards the ceiling to deepen the stretch in your hamstrings and calves.'),
('Walk Your Downward Dog',4,'Hold the pose for a few breaths, and then release by slowly walking your hands back out to a downward-facing dog position.'),
('Walking Calf Raises',1,'Walk forward and push your toe into the ground'),
('Walking Calf Raises',2,'Lift you heel off the ground each step and tense your calf muscle'),
('Walking Calf Raises',3,'Repeat on each leg and walk forward slowly'),
('Walking Lunge',1,'Take a step forward shifting your weight onto the front leg.'),
('Walking Lunge',2,'Bend the knee of the front leg so the knee of the back leg comes close to the ground.'),
('Walking Lunge',3,'Stand up and go into lunging with the opposite leg.'),
('Wall Angels',1,'Stand against a wall with your back flat, arms at 90° by your sides.'),
('Wall Angels',2,'Slowly raise arms overhead, keeping elbows and wrists in contact with the wall.'),
('Wall Angels',3,'Lower arms back down to starting position, maintaining constant wall contact throughout.'),
('Wall Sit',1,'Press your back against a wall, feet shoulder-width apart.'),
('Wall Sit',2,'Lower into a squat position, thighs parallel to the floor, knees above ankles.'),
('Wall Sit',3,'Hold the position, maintaining tension in your core and legs.'),
('Warrior One',1,'Start in mountain pose, standing with your feet hip-width apart and arms at your sides.'),
('Warrior One',2,'Step your left foot back about 3-4 feet and turn it slightly inward, while keeping your right foot facing forward.'),
('Warrior One',3,'Inhale and raise your arms overhead, then exhale and bend your right knee, bringing it directly over your ankle.'),
('Warrior One',4,'Hold the pose for a few breaths, then inhale and return to mountain pose. Repeat on the other side.'),
('Warrior Three',1,'Start in mountain pose, standing with your feet hip-width apart and arms at your sides.'),
('Warrior Three',2,'Step your left foot back about 3-4 feet and raise it off the ground, while keeping your right foot facing forward.'),
('Warrior Three',3,'Inhale and reach your arms forward, parallel to the ground.'),
('Warrior Three',4,'Exhale and hinge forward at your hips, bringing your torso parallel to the ground and extending your left leg straight back. Keep your arms and right leg straight and hold the pose for a few breaths'),
('Warrior Three',5,'inhale and return to mountain pose. Repeat on the other side.'),
('Warrior Two',1,'Start in mountain pose, standing with your feet hip-width apart and arms at your sides.'),
('Warrior Two',2,'Step your left foot back about 3-4 feet and turn it slightly inward, while keeping your right foot facing forward.'),
('Warrior Two',3,'Inhale and raise your arms to shoulder height, parallel to the ground, with your palms facing down.'),
('Warrior Two',4,'Exhale and bend your right knee, bringing it directly over your ankle while keeping your left leg straight.'),
('Warrior Two',5,'Look over your right hand and hold the pose for a few breaths, then inhale and return to mountain pose. Repeat on the other side.'),
('Weighted Chin Ups',1,'Grab the bar shoulder width apart with a supinated grip (palms facing you). Use a dip belt and the let the weight hang between your legs.'),
('Weighted Chin Ups',2,'With your body hanging and arms fully extended, pull yourself up until your chin is past the bar.'),
('Weighted Chin Ups',3,'Slowly return to starting position. Repeat.'),
('Weighted Diamond Push Ups',1,'Place a plate on your back. Position your index fingers and thumbs so they are touching, forming a diamond shape.'),
('Weighted Diamond Push Ups',2,'Use a standard push up position'),
('Weighted Diamond Push Ups',3,'Lower your chest towards your hands, keep your elbows close to your body'),
('Weighted Diamond Push Ups',4,'Stop just before your chest touches the floor, then push back up to the starting position.'),
('Weighted Forearm Plank',1,'Get into a kneeling position with both forearms pressed into the ground.'),
('Weighted Forearm Plank',2,'Place a weight plate on your back (or have a partner do it for you).'),
('Weighted Forearm Plank',3,'Hold the plank for the allotted amount of time.'),
('Weighted Hand Plank',1,'Start in a kneeling position with your hands planted on the ground.'),
('Weighted Hand Plank',2,'Place a weight plate on your back or have a friend do it for you.'),
('Weighted Hand Plank',3,'Pick your knees up off the ground. Hold in this position with a flat back.'),
('Weighted Knee Push Ups',1,'Begin in a push-up position on your knees. Break at the elbow and shoulder joint.'),
('Weighted Knee Push Ups',2,'Lower your body, keeping elbows close.'),
('Weighted Knee Push Ups',3,'Push back up to the starting position.'),
('Weighted Plank Up Down',1,'Start from a plank position. Place a plate on your back.'),
('Weighted Plank Up Down',2,'Go to one elbow then the other. Try to avoid rocking back and forth.'),
('Weighted Pull Ups',1,'Grasp the bar with an overhand grip, arms and shoulders fully extended. Weight hanging between your legs.'),
('Weighted Pull Ups',2,'Pull your body up until your chin is above the bar.'),
('Weighted Pull Ups',3,'Lower your body back to starting position.'),
('Weighted Push Ups',1,'Place your hands firmly on the ground, directly under shoulders. Place a plate on your back.'),
('Weighted Push Ups',2,'Flatten your back so your entire body is straight and slowly lower your body'),
('Weighted Push Ups',3,'Draw shoulder blades back and down, keeping elbows tucked close to your body'),
('Weighted Push Ups',4,'Exhale as you push back to the starting position.'),
('Weighted Wall Sit',1,'Press your back against a wall, feet shoulder-width apart, holding weights at your sides.'),
('Weighted Wall Sit',2,'Lower into a squat position, thighs parallel to the floor, knees above ankles.'),
('Weighted Wall Sit',3,'Hold the position, maintaining tension in your core and legs.'),
('Wide Legged Forward Fall',1,'Start standing at the top of your mat with your feet wide apart.'),
('Wide Legged Forward Fall',2,'Interlace your fingers behind your back and inhale to expand your chest.'),
('Wide Legged Forward Fall',3,'Exhale and fold forward from your hips, bringing your hands up and over your head towards the ground.'),
('Wide Legged Forward Fall',4,'Hold for a few breaths and then release the hands and come back up to standing.'),
('Wide Legged Standing Forward Bend Holding Heels',1,'Start standing at the top of your mat with your feet wide apart.'),
('Wide Legged Standing Forward Bend Holding Heels',2,'Start standing at the top of your mat with your feet wide apart.'),
('Wide Legged Standing Forward Bend Holding Heels',3,'Exhale and fold forward from your hips, bringing your hands up and over your head towards the ground.'),
('Wide Legged Standing Forward Bend Holding Heels',4,'Hold for a few breaths and then release the hands and come back up to standing.'),
('Wild Thing Pose',1,'Start in a downward facing dog position.'),
('Wild Thing Pose',2,'Shift your weight onto your left hand and foot, and lift your right leg towards the ceiling.'),
('Wild Thing Pose',3,'Slowly bend your right knee and shift your weight onto your right hand as you open up your chest towards the ceiling.'),
('Wild Thing Pose',4,'Look towards your right hand and hold the pose for a few breaths before switching sides.'),
('Windshield Wiper',1,'Lie on back, arms out, legs together.'),
('Windshield Wiper',2,'Lift legs to 90 degrees.'),
('Windshield Wiper',3,'Rotate legs side to side, keeping shoulders grounded.'),
('Yogi Arm Clock',1,'Stand facing a wall with your arms extended and your palms pressing into the wall at shoulder height.'),
('Yogi Arm Clock',2,'Slowly begin to walk your feet away from the wall, keeping your arms straight and your hands pressing into the wall.'),
('Yogi Arm Clock',3,'Walk until your arms are fully extended and your body is at a 45-degree angle to the ground.'),
('Yogi Arm Clock',4,'Repeat From High to Low Angles starting above the shoulder, and ending below the chest.');
